BEGIN;

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The electromagnetic wave with the highest penetrating power is:", "explanation": "Gamma rays have the shortest wavelength and highest frequency among EM waves, giving them the highest energy per photon (E = hf). This high energy allows them to penetrate through most materials, including metals and body tissues. X-rays also penetrate well but less than gamma rays.", "correct_answer": "D", "concept_tags": ["penetrating-power", "gamma-rays", "energy-frequency"], "payload": {"question_id": "cuet-phy-emwave-34", "subtopic": "properties of EM spectrum regions", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "understand", "options": [{"key": "A", "text": "Visible light", "is_correct": false}, {"key": "B", "text": "Infrared", "is_correct": false}, {"key": "C", "text": "X-rays", "is_correct": false}, {"key": "D", "text": "Gamma rays", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Visible light is blocked by opaque materials and has much lower photon energy than X-rays or gamma rays.", "misconception": "Thinking visible light penetrates well because we see through glass"}, {"option_key": "B", "hint": "Infrared is absorbed by most solids and has very low penetrating power compared to high-frequency radiation.", "misconception": "Confusing heat penetration with radiation penetration"}, {"option_key": "C", "hint": "X-rays have high penetrating power and are used in medical imaging, but gamma rays have even higher energy and penetrate more.", "misconception": "Thinking X-rays are the most penetrating — close but gamma rays exceed them"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Maxwell''s equations predict that the speed of electromagnetic waves in a medium of permittivity ε and permeability μ is:", "explanation": "From Maxwell''s equations, the wave speed in a medium is v = 1/√(με). In vacuum, this gives c = 1/√(μ₀ε₀) = 3 × 10⁸ m/s. In any medium, ε > ε₀ and μ > μ₀ (usually), so v < c — electromagnetic waves slow down in a medium.", "correct_answer": "A", "concept_tags": ["maxwell-speed", "permittivity", "permeability"], "payload": {"question_id": "cuet-phy-emwave-35", "subtopic": "Maxwell''s equations and wave speed", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "remember", "options": [{"key": "A", "text": "1/√(με)", "is_correct": true}, {"key": "B", "text": "√(με)", "is_correct": false}, {"key": "C", "text": "1/(με)", "is_correct": false}, {"key": "D", "text": "με", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "√(με) would give speed in units of √(H·F/m²). Dimensionally, speed should be m/s = 1/√(με).", "misconception": "Inverting the formula"}, {"option_key": "C", "hint": "1/(με) has wrong dimensions. Check: [1/(με)] = m²/(H·F) which is not m/s.", "misconception": "Forgetting the square root"}, {"option_key": "D", "hint": "με has dimensions of H·F/m² = s²/m². This is the reciprocal of speed squared, not speed.", "misconception": "Completely inverting the relationship"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The radiation pressure exerted by an electromagnetic wave of intensity I on a perfectly reflecting surface is:", "explanation": "When an EM wave of intensity I strikes a perfectly reflecting surface, the radiation pressure is p = 2I/c. For a perfectly absorbing surface, it would be I/c. The factor of 2 for reflection arises because the momentum change is doubled (like a ball bouncing off a wall vs. sticking to it).", "correct_answer": "C", "concept_tags": ["radiation-pressure", "reflection", "momentum"], "payload": {"question_id": "cuet-phy-emwave-36", "subtopic": "momentum and radiation pressure", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "apply", "options": [{"key": "A", "text": "I/c", "is_correct": false}, {"key": "B", "text": "I/c²", "is_correct": false}, {"key": "C", "text": "2I/c", "is_correct": true}, {"key": "D", "text": "Ic", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "I/c is the radiation pressure for a perfectly absorbing (black) surface. Reflection doubles the momentum transfer.", "misconception": "Using the absorption formula for reflection"}, {"option_key": "B", "hint": "I/c² has units of kg/m³, not Pa (N/m²). Dimensionally incorrect for pressure.", "misconception": "Confusing with E = mc² related expressions"}, {"option_key": "D", "hint": "Ic would have units of W²·s/m³ which is not pressure. Also, pressure should decrease with increasing c.", "misconception": "Inverting the c dependence"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Which of the following is used in the treatment of cancer?", "explanation": "Gamma rays are used in radiation therapy (radiotherapy) for cancer treatment. Their high energy and penetrating power allow them to destroy cancer cells deep within the body. Cobalt-60 is a common gamma ray source used in cancer treatment. Infrared is used for physiotherapy, UV for sterilisation, and microwaves for communication.", "correct_answer": "A", "concept_tags": ["gamma-rays", "cancer-treatment", "medical-applications"], "payload": {"question_id": "cuet-phy-emwave-37", "subtopic": "medical applications of EM waves", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "remember", "options": [{"key": "A", "text": "Gamma rays", "is_correct": true}, {"key": "B", "text": "Infrared rays", "is_correct": false}, {"key": "C", "text": "Radio waves", "is_correct": false}, {"key": "D", "text": "Microwaves", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Infrared radiation is used for heating and physiotherapy, not for destroying cancer cells.", "misconception": "Confusing thermal therapy with radiation therapy"}, {"option_key": "C", "hint": "Radio waves have very low energy and cannot damage or destroy cells. They are used in communication.", "misconception": "Thinking all radiation can treat cancer"}, {"option_key": "D", "hint": "Microwaves are used in cooking and communication. While microwave ablation exists in surgery, standard cancer radiotherapy uses gamma rays.", "misconception": "Confusing microwave heating with radiation therapy"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The source of infrared radiation is:", "explanation": "All hot bodies emit infrared radiation. Infrared is thermal radiation — any object above absolute zero emits IR, but hot bodies like heaters, the Sun, and human bodies emit significant amounts. IR is detected as heat by our skin.", "correct_answer": "B", "concept_tags": ["infrared", "thermal-radiation", "hot-bodies"], "payload": {"question_id": "cuet-phy-emwave-38", "subtopic": "sources of EM waves", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "remember", "options": [{"key": "A", "text": "Nuclear reactions", "is_correct": false}, {"key": "B", "text": "Hot bodies", "is_correct": true}, {"key": "C", "text": "X-ray tubes", "is_correct": false}, {"key": "D", "text": "Electronic oscillators", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Nuclear reactions primarily produce gamma rays, not infrared. The energy scale is completely different.", "misconception": "Confusing nuclear radiation with thermal radiation"}, {"option_key": "C", "hint": "X-ray tubes produce X-rays by bombarding a metal target with high-speed electrons, not infrared.", "misconception": "Confusing X-ray production with IR emission"}, {"option_key": "D", "hint": "Electronic oscillators produce radio waves and microwaves, not infrared.", "misconception": "Confusing electronic oscillation frequencies with thermal emission"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The momentum carried by an electromagnetic wave of energy U is:", "explanation": "Electromagnetic waves carry momentum p = U/c, where U is the energy and c is the speed of light. This follows from the relativistic energy-momentum relation for massless particles (photons): E = pc. This momentum is responsible for radiation pressure.", "correct_answer": "A", "concept_tags": ["momentum", "energy-momentum", "photon"], "payload": {"question_id": "cuet-phy-emwave-39", "subtopic": "energy and momentum of EM waves", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "remember", "options": [{"key": "A", "text": "U/c", "is_correct": true}, {"key": "B", "text": "Uc", "is_correct": false}, {"key": "C", "text": "U/c²", "is_correct": false}, {"key": "D", "text": "Uc²", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Uc has units of J·m/s = kg·m³/s³. Momentum should have units of kg·m/s.", "misconception": "Inverting the c relationship"}, {"option_key": "C", "hint": "U/c² has units of kg, which is mass — not momentum. This comes from E = mc², a different relation.", "misconception": "Confusing p = U/c with m = E/c²"}, {"option_key": "D", "hint": "Uc² has units of J·m²/s² — dimensionally incorrect for momentum.", "misconception": "Random combination of E and c"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A laser beam of power 10 W is focused on an area of 10⁻⁴ m². The amplitude of the electric field of the EM wave is approximately:", "explanation": "Intensity I = Power/Area = 10/10⁻⁴ = 10⁵ W/m². Using I = ½ε₀cE₀², we get E₀² = 2I/(ε₀c) = 2 × 10⁵/(8.85 × 10⁻¹² × 3 × 10⁸) = 2 × 10⁵/2.655 × 10⁻³ ≈ 7.53 × 10⁷. So E₀ ≈ √(7.53 × 10⁷) ≈ 8.68 × 10³ ≈ 8.7 kV/m.", "correct_answer": "C", "concept_tags": ["intensity-calculation", "electric-field-amplitude", "laser"], "payload": {"question_id": "cuet-phy-emwave-40", "subtopic": "numerical problems on intensity", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "apply", "options": [{"key": "A", "text": "8.7 V/m", "is_correct": false}, {"key": "B", "text": "87 V/m", "is_correct": false}, {"key": "C", "text": "8.7 kV/m", "is_correct": true}, {"key": "D", "text": "87 kV/m", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "8.7 V/m is 1000× too small. Check: I for E₀ = 8.7 V/m gives I ≈ 0.1 W/m², not 10⁵ W/m².", "misconception": "Order of magnitude error in calculation"}, {"option_key": "B", "hint": "87 V/m gives I ≈ 10 W/m². Still 10⁴ times less than the required 10⁵ W/m².", "misconception": "Arithmetic error — off by factor of 100"}, {"option_key": "D", "hint": "87 kV/m gives I ≈ 10⁷ W/m², which is 100× more than the given intensity.", "misconception": "Overshooting by a factor of 10 in E₀"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): Electromagnetic waves are transverse in nature.\nReason (R): The electric and magnetic field vectors are perpendicular to each other and to the direction of propagation.", "explanation": "Both A and R are true, and R correctly explains A. EM waves are transverse because E and B oscillate perpendicular to the propagation direction. This is fundamentally different from longitudinal waves (like sound) where oscillation is along the propagation direction.", "correct_answer": "A", "concept_tags": ["transverse-nature", "E-B-perpendicular", "assertion-reasoning"], "payload": {"question_id": "cuet-phy-emwave-41", "subtopic": "nature of EM waves", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are true, and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are true, but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is true but R is false", "is_correct": false}, {"key": "D", "text": "A is false but R is true", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The perpendicularity of E, B, and the propagation direction is precisely what makes the wave transverse. R directly explains A.", "misconception": "Thinking the explanation is unrelated"}, {"option_key": "C", "hint": "R is factually correct — E ⊥ B ⊥ direction of propagation is a well-established property of EM waves.", "misconception": "Doubting the perpendicularity of E and B"}, {"option_key": "D", "hint": "A is true — EM waves are indeed transverse. This is confirmed by polarisation experiments.", "misconception": "Thinking EM waves are longitudinal"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): The energy of an electromagnetic wave is shared equally between the electric and magnetic fields.\nReason (R): The electric energy density uE = ½ε₀E² equals the magnetic energy density uB = B²/(2μ₀) at every instant in an EM wave.", "explanation": "Both A and R are true, and R correctly explains A. In an EM wave, since B = E/c and c = 1/√(μ₀ε₀), we can show that ½ε₀E² = B²/(2μ₀) at every instant. The energy oscillates between zero and maximum, but at each instant the electric and magnetic contributions are exactly equal.", "correct_answer": "A", "concept_tags": ["energy-equipartition", "energy-density", "E-B-equality"], "payload": {"question_id": "cuet-phy-emwave-42", "subtopic": "energy distribution in EM waves", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "analyse", "options": [{"key": "A", "text": "Both A and R are true, and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are true, but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is true but R is false", "is_correct": false}, {"key": "D", "text": "A is false but R is true", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "R directly proves A — if uE = uB at every instant, then the energy is equally shared. R is the explanation.", "misconception": "Not seeing the direct logical connection"}, {"option_key": "C", "hint": "R is true: substituting B = E/c into B²/(2μ₀) gives E²/(2c²μ₀) = ½ε₀E² since c² = 1/(μ₀ε₀).", "misconception": "Not verifying the mathematical equality"}, {"option_key": "D", "hint": "A is true — equal energy sharing is a fundamental property derived from Maxwell''s equations.", "misconception": "Thinking one field dominates the other"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): Radio waves can diffract around buildings and hills.\nReason (R): Radio waves have wavelengths comparable to the size of buildings and hills.", "explanation": "Both A and R are true, and R correctly explains A. Radio waves have wavelengths from metres to kilometres, which are comparable to the size of buildings and hills. Diffraction is significant when the obstacle size is comparable to the wavelength, so radio waves bend around these structures. This is why AM radio signals can be received even behind mountains.", "correct_answer": "A", "concept_tags": ["radio-diffraction", "wavelength-obstacle", "diffraction"], "payload": {"question_id": "cuet-phy-emwave-43", "subtopic": "diffraction of EM waves", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are true, and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are true, but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is true but R is false", "is_correct": false}, {"key": "D", "text": "A is false but R is true", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The comparable wavelength is precisely why diffraction occurs. R is the direct cause of A.", "misconception": "Not connecting diffraction condition to wavelength"}, {"option_key": "C", "hint": "R is correct: AM radio wavelengths are ~100–1000 m, comparable to building and hill sizes.", "misconception": "Underestimating radio wavelengths"}, {"option_key": "D", "hint": "A is true — radio reception behind obstacles is daily evidence of radio wave diffraction.", "misconception": "Thinking radio needs line-of-sight"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): Displacement current does not produce a magnetic field.\nReason (R): Displacement current is not a flow of charges.", "explanation": "A is false but R is true. Displacement current IS NOT a flow of charges (R is true — it arises from changing electric field). However, displacement current DOES produce a magnetic field, exactly like conduction current (A is false). This was Maxwell''s key insight: a changing electric field between capacitor plates produces a magnetic field, maintaining the continuity of the Ampere''s circuital law.", "correct_answer": "D", "concept_tags": ["displacement-current", "maxwell-insight", "magnetic-field"], "payload": {"question_id": "cuet-phy-emwave-44", "subtopic": "displacement current and Maxwell''s correction", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "analyse", "options": [{"key": "A", "text": "Both A and R are true, and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are true, but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is true but R is false", "is_correct": false}, {"key": "D", "text": "A is false but R is true", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "A is false — displacement current does produce a magnetic field. That''s the whole point of Maxwell''s modification to Ampere''s law.", "misconception": "Thinking displacement current has no magnetic effect"}, {"option_key": "B", "hint": "A is false, so this option cannot be correct.", "misconception": "Same as above"}, {"option_key": "C", "hint": "R is true — displacement current is ε₀(dΦE/dt), not a flow of actual charges. It exists even in vacuum.", "misconception": "Confusing displacement current with conduction current"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match the following electromagnetic waves (Column-I) with their sources (Column-II):\n\nColumn-I: (P) Radio waves (Q) X-rays (R) Gamma rays (S) Infrared\nColumn-II: (1) Radioactive nuclei (2) Vibration of atoms/molecules (3) Accelerating electrons striking metal target (4) Oscillating electric circuits", "explanation": "P→4: Radio waves are produced by oscillating charges in LC circuits and antennas. Q→3: X-rays are produced when high-speed electrons decelerate upon hitting a metal target (Bremsstrahlung). R→1: Gamma rays originate from nuclear transitions in radioactive decay. S→2: Infrared radiation is emitted by vibrating atoms and molecules (thermal motion).", "correct_answer": "B", "concept_tags": ["sources", "matching", "spectrum-production"], "payload": {"question_id": "cuet-phy-emwave-45", "subtopic": "sources of different EM waves", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "remember", "options": [{"key": "A", "text": "P→1, Q→3, R→4, S→2", "is_correct": false}, {"key": "B", "text": "P→4, Q→3, R→1, S→2", "is_correct": true}, {"key": "C", "text": "P→4, Q→1, R→3, S→2", "is_correct": false}, {"key": "D", "text": "P→2, Q→3, R→1, S→4", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "P→1 means radio waves from radioactive nuclei — incorrect. Nuclear decay produces gamma rays, not radio waves.", "misconception": "Confusing nuclear radiation with radio transmission"}, {"option_key": "C", "hint": "Q→1 implies X-rays from radioactive nuclei. While some nuclei emit X-rays, the primary source is electron deceleration in X-ray tubes (3).", "misconception": "Confusing gamma emission with X-ray production"}, {"option_key": "D", "hint": "P→2 means radio waves from atomic vibrations — incorrect. Atomic vibrations produce infrared, not radio waves.", "misconception": "Confusing thermal radiation with radio waves"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "hard", "question_text": "Match the following electromagnetic waves (Column-I) with their approximate frequency ranges (Column-II):\n\nColumn-I: (P) Microwaves (Q) Visible light (R) Ultraviolet (S) X-rays\nColumn-II: (1) 10¹⁵ to 10¹⁷ Hz (2) 4 × 10¹⁴ to 7.5 × 10¹⁴ Hz (3) 10⁹ to 10¹² Hz (4) 10¹⁷ to 10²⁰ Hz", "explanation": "P→3: Microwaves have frequencies from ~10⁹ to 10¹² Hz (GHz range). Q→2: Visible light spans ~4 × 10¹⁴ Hz (red) to ~7.5 × 10¹⁴ Hz (violet). R→1: UV radiation spans ~10¹⁵ to 10¹⁷ Hz. S→4: X-rays have frequencies from ~10¹⁷ to 10²⁰ Hz.", "correct_answer": "A", "concept_tags": ["frequency-ranges", "spectrum-ordering", "matching"], "payload": {"question_id": "cuet-phy-emwave-46", "subtopic": "frequency ranges of EM spectrum", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "remember", "options": [{"key": "A", "text": "P→3, Q→2, R→1, S→4", "is_correct": true}, {"key": "B", "text": "P→3, Q→1, R→2, S→4", "is_correct": false}, {"key": "C", "text": "P→2, Q→3, R→1, S→4", "is_correct": false}, {"key": "D", "text": "P→3, Q→2, R→4, S→1", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Q→1 assigns 10¹⁵–10¹⁷ Hz to visible light, which is actually the UV range. Visible is only ~4–7.5 × 10¹⁴ Hz.", "misconception": "Overestimating visible light frequency"}, {"option_key": "C", "hint": "P→2 assigns ~10¹⁴ Hz to microwaves. Microwaves are much lower frequency (~10⁹–10¹² Hz).", "misconception": "Confusing microwave and visible frequencies"}, {"option_key": "D", "hint": "R→4 assigns 10¹⁷–10²⁰ Hz to UV, but that''s the X-ray range. UV is lower frequency than X-rays.", "misconception": "Swapping UV and X-ray frequency ranges"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match the following EM wave applications (Column-I) with the type of EM wave used (Column-II):\n\nColumn-I: (P) Night vision cameras (Q) Satellite communication (R) Sterilisation of surgical instruments (S) Medical imaging of bones\nColumn-II: (1) X-rays (2) Ultraviolet (3) Microwaves (4) Infrared", "explanation": "P→4: Night vision uses infrared cameras to detect heat emitted by bodies. Q→3: Satellite communication uses microwaves which can penetrate the ionosphere. R→2: UV radiation kills bacteria and is used for sterilisation. S→1: X-rays penetrate soft tissue but are absorbed by bones, creating contrast images.", "correct_answer": "C", "concept_tags": ["applications", "matching", "practical-uses"], "payload": {"question_id": "cuet-phy-emwave-47", "subtopic": "applications of EM spectrum", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "remember", "options": [{"key": "A", "text": "P→4, Q→3, R→1, S→2", "is_correct": false}, {"key": "B", "text": "P→3, Q→4, R→2, S→1", "is_correct": false}, {"key": "C", "text": "P→4, Q→3, R→2, S→1", "is_correct": true}, {"key": "D", "text": "P→4, Q→2, R→3, S→1", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "R→1 means sterilisation with X-rays — UV is the standard sterilisation method, not X-rays.", "misconception": "Confusing X-ray imaging with UV sterilisation"}, {"option_key": "B", "hint": "P→3 means night vision with microwaves — night vision cameras detect infrared (heat), not microwaves.", "misconception": "Confusing thermal IR with microwave detection"}, {"option_key": "D", "hint": "Q→2 means satellite communication with UV — UV is absorbed by the atmosphere. Microwaves pass through.", "misconception": "Thinking UV can be used for long-range communication"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "Electromagnetic waves require a material medium for their propagation.", "explanation": "This statement is FALSE. Electromagnetic waves are self-sustaining oscillations of electric and magnetic fields and do NOT require a material medium. They can propagate through vacuum at the speed of light. This is fundamentally different from mechanical waves like sound, which need a medium.", "correct_answer": "B", "concept_tags": ["vacuum-propagation", "no-medium", "em-vs-mechanical"], "payload": {"question_id": "cuet-phy-emwave-48", "subtopic": "properties of EM waves", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Sunlight reaches us through the vacuum of space — clear proof that EM waves don''t need a medium.", "misconception": "Confusing EM waves with sound waves which do need a medium"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "X-rays have a higher frequency than ultraviolet rays.", "explanation": "This statement is TRUE. In the EM spectrum, frequency increases as: radio < microwave < IR < visible < UV < X-rays < gamma rays. X-rays (10¹⁷–10²⁰ Hz) have higher frequency than UV (10¹⁵–10¹⁷ Hz).", "correct_answer": "A", "concept_tags": ["frequency-ordering", "x-rays-vs-uv", "spectrum"], "payload": {"question_id": "cuet-phy-emwave-49", "subtopic": "EM spectrum ordering", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "X-rays are more energetic than UV — since E = hf, higher energy means higher frequency.", "misconception": "Reversing the order of X-rays and UV in the spectrum"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "medium", "question_text": "In an electromagnetic wave, the electric and magnetic fields are in phase with each other.", "explanation": "This statement is TRUE. In an EM wave, E and B reach their maximum, minimum, and zero values simultaneously — they oscillate in phase. If E = E₀ sin(kx − ωt), then B = B₀ sin(kx − ωt) with the same phase. They differ in direction (perpendicular) and magnitude (B₀ = E₀/c), but not in phase.", "correct_answer": "A", "concept_tags": ["phase-relation", "E-B-in-phase", "wave-properties"], "payload": {"question_id": "cuet-phy-emwave-50", "subtopic": "phase relationship in EM waves", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Unlike standing waves or LC oscillations where E and B are 90° out of phase, in a travelling EM wave they are always in phase.", "misconception": "Confusing travelling wave with standing wave or LC circuit phase relations"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "medium", "question_text": "The displacement current between the plates of a charging capacitor is equal to the conduction current in the external circuit.", "explanation": "This statement is TRUE. Maxwell showed that the displacement current Id = ε₀(dΦE/dt) between the capacitor plates equals the conduction current Ic in the connecting wires. This ensures continuity of current through the circuit, including the gap between the capacitor plates where no charges actually flow.", "correct_answer": "A", "concept_tags": ["displacement-current", "conduction-current", "continuity"], "payload": {"question_id": "cuet-phy-emwave-51", "subtopic": "displacement current", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "If Id ≠ Ic, Kirchhoff''s current law would be violated at the capacitor terminals. Maxwell''s correction precisely ensures Id = Ic.", "misconception": "Thinking current is discontinuous at capacitor plates"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "easy", "question_text": "The part of the electromagnetic spectrum used in television remote controls is ______.", "explanation": "Television remote controls use infrared (IR) radiation. They emit IR light pulses in coded patterns that are received by an IR sensor on the TV. IR is used because it is invisible, safe, low-power, and works well over short distances within a room.", "correct_answer": "C", "concept_tags": ["infrared", "remote-control", "applications"], "payload": {"question_id": "cuet-phy-emwave-52", "subtopic": "everyday applications of EM waves", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "remember", "options": [{"key": "A", "text": "Radio waves", "is_correct": false}, {"key": "B", "text": "Microwaves", "is_correct": false}, {"key": "C", "text": "Infrared", "is_correct": true}, {"key": "D", "text": "Ultraviolet", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Radio waves are used for broadcast communication (FM/AM radio, WiFi), not for TV remote controls.", "misconception": "Confusing radio broadcast with remote control"}, {"option_key": "B", "hint": "Microwaves are used in ovens and long-distance communication, not in handheld remote controls.", "misconception": "Confusing different wireless technologies"}, {"option_key": "D", "hint": "UV radiation can be harmful to eyes and skin. It would be unsafe and impractical for a consumer remote control.", "misconception": "Thinking any invisible radiation works for remotes"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "Maxwell added ______ current to Ampere''s circuital law to make it consistent for both steady and time-varying fields.", "explanation": "Maxwell added the displacement current (Id = ε₀ dΦE/dt) to Ampere''s circuital law. The original law worked for steady currents but failed for time-varying fields (e.g., between capacitor plates during charging). The modified law is: ∮B·dl = μ₀(Ic + Id), where Ic is conduction current and Id is displacement current.", "correct_answer": "B", "concept_tags": ["displacement-current", "ampere-law", "maxwell-correction"], "payload": {"question_id": "cuet-phy-emwave-53", "subtopic": "Maxwell''s modification of Ampere''s law", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "remember", "options": [{"key": "A", "text": "Conduction", "is_correct": false}, {"key": "B", "text": "Displacement", "is_correct": true}, {"key": "C", "text": "Convection", "is_correct": false}, {"key": "D", "text": "Eddy", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Conduction current was already in the original Ampere''s law. Maxwell added something new, not what was already there.", "misconception": "Confusing existing term with the new addition"}, {"option_key": "C", "hint": "Convection current refers to charge transport in fluids. It is not related to Maxwell''s theoretical correction.", "misconception": "Random guess among current types"}, {"option_key": "D", "hint": "Eddy currents are induced circular currents in conductors, related to Faraday''s law — not Maxwell''s correction to Ampere''s law.", "misconception": "Confusing Faraday''s law effects with Maxwell''s addition"}]}}]'::jsonb, 'deploy-2026-03-05-b07');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "The speed of light in vacuum, c = 1/√(μ₀ε₀), has a value of approximately ______ m/s.", "explanation": "Using μ₀ = 4π × 10⁻⁷ H/m and ε₀ = 8.854 × 10⁻¹² F/m, c = 1/√(μ₀ε₀) = 1/√(4π × 10⁻⁷ × 8.854 × 10⁻¹²) ≈ 3 × 10⁸ m/s. This value was calculated by Maxwell and matched the experimentally known speed of light, leading him to conclude that light is an electromagnetic wave.", "correct_answer": "A", "concept_tags": ["speed-of-light", "mu-epsilon", "maxwell-prediction"], "payload": {"question_id": "cuet-phy-emwave-54", "subtopic": "derivation of speed of light", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "remember", "options": [{"key": "A", "text": "3 × 10⁸", "is_correct": true}, {"key": "B", "text": "3 × 10⁶", "is_correct": false}, {"key": "C", "text": "3 × 10¹⁰", "is_correct": false}, {"key": "D", "text": "3 × 10⁵", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "3 × 10⁶ m/s is about 1% of the speed of light. Light travels ~300,000 km/s, not 3,000 km/s.", "misconception": "Off by a factor of 100"}, {"option_key": "C", "hint": "3 × 10¹⁰ m/s exceeds the speed of light by 100×. Nothing can travel this fast according to relativity.", "misconception": "Confusing with c in cm/s (3 × 10¹⁰ cm/s)"}, {"option_key": "D", "hint": "3 × 10⁵ m/s is approximately the speed of sound in some metals, not the speed of light.", "misconception": "Off by three orders of magnitude"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET"], "question_type": "scenario-based", "difficulty": "medium", "question_text": "A student is studying the electromagnetic spectrum and notes the following observations:\n(i) A TV remote works by emitting invisible radiation detected by a sensor on the TV.\n(ii) Mobile phones use radiation that can pass through walls but has less energy than light.\n(iii) Hospital X-ray machines can see through skin but not through bones.\n\nWhich of the following correctly identifies all three types of radiation?", "explanation": "(i) TV remotes use infrared radiation — invisible, low energy, short range. (ii) Mobile phones use microwaves — they can penetrate walls, have lower frequency (hence lower energy) than visible light. (iii) X-rays penetrate soft tissue but are absorbed by dense bone, creating contrast images. The correct identification is IR, Microwaves, X-rays.", "correct_answer": "B", "concept_tags": ["spectrum-identification", "real-world", "scenario"], "payload": {"question_id": "cuet-phy-emwave-55", "subtopic": "identifying EM waves from properties", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "apply", "options": [{"key": "A", "text": "(i) UV, (ii) Radio waves, (iii) X-rays", "is_correct": false}, {"key": "B", "text": "(i) Infrared, (ii) Microwaves, (iii) X-rays", "is_correct": true}, {"key": "C", "text": "(i) Infrared, (ii) Radio waves, (iii) Gamma rays", "is_correct": false}, {"key": "D", "text": "(i) Radio waves, (ii) Microwaves, (iii) X-rays", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "UV is not used in TV remotes — it would be harmful to emit UV radiation directly at people. Remotes use safe infrared.", "misconception": "Confusing invisible UV with invisible IR"}, {"option_key": "C", "hint": "Mobile phones use microwaves (GHz range), not radio waves (MHz range). Also, hospital imaging uses X-rays, not gamma rays.", "misconception": "Confusing microwave with radio, and X-ray with gamma"}, {"option_key": "D", "hint": "TV remotes emit infrared, not radio waves. Radio waves have much longer wavelengths and are used for broadcasting.", "misconception": "Thinking any wireless device uses radio waves"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "hard", "question_text": "A parallel plate capacitor with plate area A = 2 × 10⁻² m² is being charged by a current of 0.5 A. The electric field between the plates changes uniformly.\n\nThe displacement current between the plates is:", "explanation": "The displacement current Id between capacitor plates equals the conduction current Ic in the external circuit (Maxwell''s continuity principle). Since Ic = 0.5 A, Id = 0.5 A. This can be verified: Id = ε₀(dΦE/dt) = ε₀A(dE/dt). Since the charging current provides dQ/dt = 0.5 A, and Q = ε₀AE, we get ε₀A(dE/dt) = dQ/dt = 0.5 A.", "correct_answer": "B", "concept_tags": ["displacement-current-calculation", "capacitor-charging", "maxwell"], "payload": {"question_id": "cuet-phy-emwave-56", "subtopic": "displacement current numerical", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "apply", "options": [{"key": "A", "text": "0.25 A", "is_correct": false}, {"key": "B", "text": "0.5 A", "is_correct": true}, {"key": "C", "text": "1.0 A", "is_correct": false}, {"key": "D", "text": "Depends on the plate area", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Id = Ic always (for a charging capacitor). The displacement current is NOT half the conduction current.", "misconception": "Thinking displacement current is half of conduction current"}, {"option_key": "C", "hint": "Id = Ic = 0.5 A, not 2 × Ic. There is no doubling factor in the Id-Ic relationship.", "misconception": "Doubling the current incorrectly"}, {"option_key": "D", "hint": "While ε₀A(dE/dt) depends on area, the result always equals Ic regardless of plate dimensions. The area cancels out.", "misconception": "Thinking displacement current depends on plate geometry independently of conduction current"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET"], "question_type": "scenario-based", "difficulty": "hard", "question_text": "An astronaut on the International Space Station communicates with ground control using radio signals. The ISS orbits at a height of approximately 400 km above Earth''s surface.\n\nThe time delay for the radio signal to travel from ISS to Earth is approximately:", "explanation": "Radio signals travel at the speed of light, c = 3 × 10⁸ m/s. Distance = 400 km = 4 × 10⁵ m. Time = distance/speed = 4 × 10⁵/(3 × 10⁸) = 1.33 × 10⁻³ s ≈ 1.3 ms. This is barely perceptible in conversation.", "correct_answer": "B", "concept_tags": ["speed-distance-time", "space-communication", "practical"], "payload": {"question_id": "cuet-phy-emwave-57", "subtopic": "EM wave speed applications", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "apply", "options": [{"key": "A", "text": "0.13 ms", "is_correct": false}, {"key": "B", "text": "1.3 ms", "is_correct": true}, {"key": "C", "text": "13 ms", "is_correct": false}, {"key": "D", "text": "1.3 s", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "0.13 ms corresponds to only 40 km distance, not 400 km. Check the exponent calculation.", "misconception": "Error in power of ten"}, {"option_key": "C", "hint": "13 ms corresponds to ~4000 km, which is 10× the actual ISS height.", "misconception": "Using 4 × 10⁶ m instead of 4 × 10⁵ m"}, {"option_key": "D", "hint": "1.3 s would mean a distance of ~400,000 km — roughly the Earth-Moon distance, not ISS height.", "misconception": "Major order of magnitude error"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A plane EM wave has an electric field amplitude of 480 V/m. The magnetic field amplitude and the average intensity of the wave are respectively:", "explanation": "B₀ = E₀/c = 480/(3 × 10⁸) = 1.6 × 10⁻⁶ T. Average intensity I = ½ε₀cE₀² = ½ × 8.85 × 10⁻¹² × 3 × 10⁸ × (480)² = ½ × 8.85 × 10⁻¹² × 3 × 10⁸ × 2.304 × 10⁵ = ½ × 611.5 ≈ 306 W/m².", "correct_answer": "A", "concept_tags": ["numerical", "B-amplitude", "intensity-calculation"], "payload": {"question_id": "cuet-phy-emwave-58", "subtopic": "E, B amplitude and intensity", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "apply", "options": [{"key": "A", "text": "1.6 × 10⁻⁶ T, 306 W/m²", "is_correct": true}, {"key": "B", "text": "1.6 × 10⁻⁶ T, 612 W/m²", "is_correct": false}, {"key": "C", "text": "1.6 × 10⁻⁸ T, 306 W/m²", "is_correct": false}, {"key": "D", "text": "1.6 × 10⁻⁶ T, 153 W/m²", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "612 W/m² is the peak intensity (ε₀cE₀²), not the average. For average, you need the ½ factor from time-averaging sin².", "misconception": "Forgetting the ½ factor in average intensity"}, {"option_key": "C", "hint": "1.6 × 10⁻⁸ T is 100× too small. B₀ = E₀/c = 480/(3×10⁸) = 1.6 × 10⁻⁶ T.", "misconception": "Arithmetic error in exponents: 10⁰/10⁸ ≠ 10⁻⁸ for this calculation"}, {"option_key": "D", "hint": "153 W/m² is ¼ε₀cE₀², which counts only the electric field contribution. Total intensity includes both E and B.", "misconception": "Forgetting to add the magnetic field energy contribution"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Which property of electromagnetic waves proves that they are transverse?", "explanation": "Polarisation is exclusively a property of transverse waves. Only waves whose oscillations are perpendicular to the propagation direction can be polarised (restricted to a single plane). Longitudinal waves like sound cannot be polarised. The fact that light can be polarised (using Polaroid filters, for example) proves it is transverse.", "correct_answer": "C", "concept_tags": ["polarisation", "transverse-proof", "wave-nature"], "payload": {"question_id": "cuet-phy-emwave-59", "subtopic": "evidence for transverse nature", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "understand", "options": [{"key": "A", "text": "Reflection", "is_correct": false}, {"key": "B", "text": "Diffraction", "is_correct": false}, {"key": "C", "text": "Polarisation", "is_correct": true}, {"key": "D", "text": "Interference", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Both transverse and longitudinal waves can be reflected. Reflection doesn''t distinguish wave type.", "misconception": "Thinking reflection is unique to transverse waves"}, {"option_key": "B", "hint": "Diffraction occurs for all types of waves — it proves wave nature but not transverse nature.", "misconception": "Confusing wave nature with transverse nature"}, {"option_key": "D", "hint": "Interference occurs for both longitudinal and transverse waves (e.g., sound interference). It proves wave nature, not transverse nature.", "misconception": "Confusing general wave properties with transverse-specific properties"}]}}, {"chapter_id": "cuet-phy-em-waves", "topic_id": "cuet-phy-emwave-spectrum", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The electric field of a sinusoidal EM wave in vacuum obeys the equation E = 100 sin(5 × 10⁶ t − kx) V/m. The wavelength of the wave is:", "explanation": "From the equation, ω = 5 × 10⁶ rad/s. Frequency f = ω/(2π) = 5 × 10⁶/(2π) Hz. Using c = fλ, we get λ = c/f = 2πc/ω = 2π × 3 × 10⁸/(5 × 10⁶) = 6π × 10⁸/5 × 10⁶ = 6π × 10² ≈ 120π m ≈ 377 m. Alternatively, k = ω/c = 5 × 10⁶/(3 × 10⁸) = 1.67 × 10⁻² rad/m, and λ = 2π/k = 2π/(1.67 × 10⁻²) ≈ 376.8 m.", "correct_answer": "D", "concept_tags": ["wave-equation", "wavelength-from-omega", "numerical"], "payload": {"question_id": "cuet-phy-emwave-60", "subtopic": "EM wave equation analysis", "topic_name": "Electromagnetic Spectrum and Wave Properties", "bloom_level": "apply", "options": [{"key": "A", "text": "60 m", "is_correct": false}, {"key": "B", "text": "60π m", "is_correct": false}, {"key": "C", "text": "12π m", "is_correct": false}, {"key": "D", "text": "120π m", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "60 m forgets the 2π factor. λ = 2πc/ω, not c/ω.", "misconception": "Using λ = c/ω instead of λ = 2πc/ω"}, {"option_key": "B", "hint": "60π m uses λ = πc/ω. The correct formula is λ = 2πc/ω = 2π × 3 × 10⁸/(5 × 10⁶).", "misconception": "Using π instead of 2π"}, {"option_key": "C", "hint": "12π m comes from an error in the power of ten: 10⁸/10⁶ = 10² = 100, not 10.", "misconception": "Arithmetic error in exponent subtraction"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "A body has a charge of −3.2 × 10⁻¹⁸ C. The number of excess electrons on the body is:", "explanation": "Number of excess electrons = Total charge / Charge of one electron = (3.2 × 10⁻¹⁸) / (1.6 × 10⁻¹⁹) = 20. The negative sign indicates excess electrons. So the body has 20 excess electrons.", "correct_answer": "B", "concept_tags": ["quantization", "electron-count"], "payload": {"question_id": "cuet-phy-elec-coulomb-01", "subtopic": "Coulomb''s Law and Electric Charges", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "apply", "options": [{"key": "A", "text": "10", "is_correct": false}, {"key": "B", "text": "20", "is_correct": true}, {"key": "C", "text": "30", "is_correct": false}, {"key": "D", "text": "200", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "10 × 1.6 × 10⁻¹⁹ = 1.6 × 10⁻¹⁸ C, which doesn''t match the given charge of 3.2 × 10⁻¹⁸ C.", "misconception": "Arithmetic error in division"}, {"option_key": "C", "hint": "30 × 1.6 × 10⁻¹⁹ = 4.8 × 10⁻¹⁸ C, which exceeds the given charge.", "misconception": null}, {"option_key": "D", "hint": "200 would give 200 × 1.6 × 10⁻¹⁹ = 3.2 × 10⁻¹⁷ C — an order of magnitude too large.", "misconception": "Error in handling powers of 10"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Which of the following is the smallest unit of charge found in nature (free state)?", "explanation": "The smallest unit of free charge in nature is the electronic charge, e = 1.6 × 10⁻¹⁹ C. Quarks carry fractional charges (e/3, 2e/3) but they do not exist in free state — they are always confined within hadrons. Hence, the electron charge is the smallest free charge.", "correct_answer": "C", "concept_tags": ["quantization-of-charge", "electronic-charge"], "payload": {"question_id": "cuet-phy-elec-coulomb-02", "subtopic": "Coulomb''s Law and Electric Charges", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "remember", "options": [{"key": "A", "text": "1 coulomb", "is_correct": false}, {"key": "B", "text": "1 microcoulomb", "is_correct": false}, {"key": "C", "text": "1.6 × 10⁻¹⁹ C", "is_correct": true}, {"key": "D", "text": "1.6 × 10⁻²⁰ C", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "1 coulomb is a macroscopic unit — it equals ~6.25 × 10¹⁸ electron charges, far too large to be the smallest.", "misconception": "Thinking the SI unit itself is the smallest charge"}, {"option_key": "B", "hint": "1 μC = 10⁻⁶ C is still billions of electron charges, not the fundamental unit.", "misconception": null}, {"option_key": "D", "hint": "This value doesn''t correspond to any fundamental charge — the correct value is 1.6 × 10⁻¹⁹ C, not 10⁻²⁰.", "misconception": "Confusion in the power of ten"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "In the process of charging by induction, the total charge of the system:", "explanation": "Charging by induction does not involve transfer of charge from the charging body. The induced body''s charges get redistributed, and when grounded, opposite charges flow in/out. The charging body retains its original charge throughout. The total charge of the complete system remains conserved.", "correct_answer": "D", "concept_tags": ["charging-by-induction", "conservation-of-charge"], "payload": {"question_id": "cuet-phy-elec-coulomb-03", "subtopic": "Coulomb''s Law and Electric Charges", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "Increases", "is_correct": false}, {"key": "B", "text": "Decreases", "is_correct": false}, {"key": "C", "text": "Becomes zero", "is_correct": false}, {"key": "D", "text": "Remains conserved", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Charge cannot be created — the law of conservation of charge prohibits any increase in total charge.", "misconception": "Thinking induction creates new charges"}, {"option_key": "B", "hint": "Charge is never destroyed in any process. The total charge of the universe is constant.", "misconception": "Confusing redistribution with destruction"}, {"option_key": "C", "hint": "Total charge becoming zero would violate conservation — if the charging body had charge Q, it still has Q after induction.", "misconception": "Thinking induced charges cancel the source charge"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Two glass rods, each rubbed with silk, are brought close to each other. They will:", "explanation": "Both glass rods acquire the same type of positive charge when rubbed with silk. Like charges repel each other, so the two rods will repel.", "correct_answer": "B", "concept_tags": ["like-charges", "charging-by-friction", "repulsion"], "payload": {"question_id": "cuet-phy-elec-coulomb-04", "subtopic": "Properties of electric charge", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "remember", "options": [{"key": "A", "text": "Attract each other", "is_correct": false}, {"key": "B", "text": "Repel each other", "is_correct": true}, {"key": "C", "text": "First attract then repel", "is_correct": false}, {"key": "D", "text": "Have no effect on each other", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Attraction occurs between unlike charges. Both rods rubbed with silk acquire the same sign (positive), so they cannot attract.", "misconception": "Confusing like and unlike charge interactions"}, {"option_key": "C", "hint": "There is no mechanism for alternating attraction and repulsion between static charges of the same sign.", "misconception": null}, {"option_key": "D", "hint": "Charged bodies always exert electrostatic forces on each other — they cannot be neutral to one another.", "misconception": "Thinking charged bodies may not interact"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The dimensional formula of permittivity of free space (ε₀) is:", "explanation": "From Coulomb''s law, F = q₁q₂/(4πε₀r²), we get ε₀ = q₁q₂/(4πFr²). Dimensions: [A²T²]/([MLT⁻²][L²]) = [M⁻¹L⁻³T⁴A²]. This can also be derived from ε₀ = 1/(μ₀c²).", "correct_answer": "C", "concept_tags": ["permittivity", "dimensional-analysis", "SI-units"], "payload": {"question_id": "cuet-phy-elec-coulomb-05", "subtopic": "Coulomb''s constant and permittivity", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "remember", "options": [{"key": "A", "text": "[ML³T⁻⁴A⁻²]", "is_correct": false}, {"key": "B", "text": "[M⁻¹L⁻³T³A²]", "is_correct": false}, {"key": "C", "text": "[M⁻¹L⁻³T⁴A²]", "is_correct": true}, {"key": "D", "text": "[MLT⁻²A⁻²]", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This has positive powers of M and L, which would give units of energy × length. Permittivity has inverse mass and inverse length cubed.", "misconception": "Inverting the formula — using dimensions of 1/ε₀ instead of ε₀"}, {"option_key": "B", "hint": "The time exponent should be T⁴, not T³. This comes from charge² = (AT)² = A²T² in the numerator.", "misconception": "Forgetting that charge = current × time, so q² contributes T² not T"}, {"option_key": "D", "hint": "These are the dimensions of force/current², not permittivity. Permittivity has negative powers of M.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Two charges Q₁ and Q₂ are separated by a distance d. A third charge Q₃ is placed between them on the line joining them such that the system is in equilibrium. The ratio Q₁/Q₂ must be:", "explanation": "For equilibrium, Q₃ must be between Q₁ and Q₂ (so they must be like charges). If Q₃ is at distance x from Q₁, then kQ₁Q₃/x² = kQ₂Q₃/(d−x)². This gives Q₁/Q₂ = x²/(d−x)². The ratio depends on x, but importantly Q₁/Q₂ must be positive (both same sign). The exact ratio is determined by the position of Q₃.", "correct_answer": "A", "concept_tags": ["equilibrium", "coulomb-law", "charge-configuration"], "payload": {"question_id": "cuet-phy-elec-coulomb-06", "subtopic": "Coulomb''s Law and Electric Charges", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "analyze", "options": [{"key": "A", "text": "Positive (both charges must have the same sign)", "is_correct": true}, {"key": "B", "text": "Negative (charges must have opposite signs)", "is_correct": false}, {"key": "C", "text": "Equal to 1 (charges must be equal)", "is_correct": false}, {"key": "D", "text": "Can be any value (no restriction)", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "If Q₁ and Q₂ have opposite signs, they attract each other. No position of Q₃ between them can balance both forces — it would be pushed toward one side.", "misconception": "Not considering force directions for unlike charges"}, {"option_key": "C", "hint": "Q₁ and Q₂ need not be equal — they just need to be the same sign. Unequal like charges can still have an equilibrium point (just not at the midpoint).", "misconception": "Assuming equilibrium requires equal charges"}, {"option_key": "D", "hint": "There is definitely a restriction — opposite charges cannot produce equilibrium for a charge placed between them.", "misconception": "Ignoring the direction of forces in equilibrium analysis"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The ratio of the electrostatic force to the gravitational force between an electron and a proton is of the order of:", "explanation": "Electrostatic force: Fe = ke²/r². Gravitational force: Fg = Gmemp/r². The ratio Fe/Fg = ke²/(Gmemp) ≈ (9×10⁹)(1.6×10⁻¹⁹)²/[(6.67×10⁻¹¹)(9.1×10⁻³¹)(1.67×10⁻²⁷)] ≈ 2.3×10³⁹. This shows electrostatic force is enormously stronger than gravity at the atomic scale.", "correct_answer": "D", "concept_tags": ["coulomb-vs-gravity", "force-comparison"], "payload": {"question_id": "cuet-phy-elec-coulomb-07", "subtopic": "Coulomb''s Law and Electric Charges", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "apply", "options": [{"key": "A", "text": "10⁹", "is_correct": false}, {"key": "B", "text": "10¹⁸", "is_correct": false}, {"key": "C", "text": "10²⁷", "is_correct": false}, {"key": "D", "text": "10³⁹", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "10⁹ is far too small — this would mean the two forces are relatively close, but electrostatic force is overwhelmingly stronger.", "misconception": "Confusing the magnitude of k itself with the force ratio"}, {"option_key": "B", "hint": "10¹⁸ is still about 21 orders of magnitude too small. The actual ratio involves masses in the denominator which are extremely tiny.", "misconception": null}, {"option_key": "C", "hint": "10²⁷ is closer but still ~12 orders too small. The product memp in the denominator is ~10⁻⁵⁸, which pushes the ratio much higher.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The force between two charges in vacuum is F. If the entire space between them is filled with a medium of relative permittivity εᵣ = 4, the new force is:", "explanation": "In a dielectric medium, the force between charges becomes F'' = F/εᵣ. Here εᵣ = 4, so F'' = F/4. The dielectric reduces the electrostatic force because the medium gets polarised and partially cancels the applied field.", "correct_answer": "A", "concept_tags": ["dielectric-medium", "permittivity", "force-reduction"], "payload": {"question_id": "cuet-phy-elec-coulomb-08", "subtopic": "Coulomb''s Law and Electric Charges", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "apply", "options": [{"key": "A", "text": "F/4", "is_correct": true}, {"key": "B", "text": "4F", "is_correct": false}, {"key": "C", "text": "F/16", "is_correct": false}, {"key": "D", "text": "16F", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The dielectric reduces the force, not increases it. Multiplying by εᵣ would mean the medium strengthens the force, which is incorrect.", "misconception": "Confusing whether εᵣ goes in numerator or denominator"}, {"option_key": "C", "hint": "F/16 would apply if the force were divided by εᵣ² = 16, but Coulomb''s law divides by εᵣ (first power), not εᵣ².", "misconception": "Incorrectly squaring the dielectric constant"}, {"option_key": "D", "hint": "16F is εᵣ² times the original force — both the direction (increase) and the power are wrong.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A charge q is placed at the centre of a line joining two equal charges Q. The system of three charges will be in equilibrium if q equals:", "explanation": "For the charge Q at one end to be in equilibrium: Force due to the other Q (repulsive) = Force due to q (attractive, so q must be negative). kQ²/(2a)² = kqQ/a² → Q/4 = q → q = −Q/4. The negative sign is essential because q must attract Q to counterbalance the repulsion from the other Q.", "correct_answer": "B", "concept_tags": ["equilibrium", "three-charge-system"], "payload": {"question_id": "cuet-phy-elec-coulomb-09", "subtopic": "Coulomb''s Law and Electric Charges", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "apply", "options": [{"key": "A", "text": "−Q/2", "is_correct": false}, {"key": "B", "text": "−Q/4", "is_correct": true}, {"key": "C", "text": "+Q/4", "is_correct": false}, {"key": "D", "text": "+Q/2", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "−Q/2 would make the attractive force on Q from q twice as large as needed, since kQ(Q/2)/a² ≠ kQ²/4a².", "misconception": "Error in setting up force balance — not accounting for the 2a distance properly"}, {"option_key": "C", "hint": "A positive charge at the centre would repel both Q charges outward, adding to the instability rather than creating equilibrium.", "misconception": "Forgetting that q must attract Q to counter the repulsion"}, {"option_key": "D", "hint": "+Q/2 at the centre would push both Q charges apart — equilibrium requires an attractive (negative) charge at the centre.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Two point charges attract each other with force F at a certain distance. If the magnitude of one charge is doubled and the distance is tripled, the new force is:", "explanation": "Original: F = kq₁q₂/r². New: F'' = k(2q₁)q₂/(3r)² = 2kq₁q₂/9r² = 2F/9. Doubling one charge doubles the force, tripling the distance reduces it by 9, net effect is 2/9.", "correct_answer": "B", "concept_tags": ["coulomb-law", "inverse-square", "proportionality"], "payload": {"question_id": "cuet-phy-elec-coulomb-10", "subtopic": "Coulomb''s law applications", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "apply", "options": [{"key": "A", "text": "2F/3", "is_correct": false}, {"key": "B", "text": "2F/9", "is_correct": true}, {"key": "C", "text": "F/9", "is_correct": false}, {"key": "D", "text": "F/3", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "2F/3 results from dividing by 3 (first power) instead of 3² = 9. Coulomb''s law has inverse square dependence.", "misconception": "Using inverse distance instead of inverse square distance"}, {"option_key": "C", "hint": "F/9 accounts for tripling the distance but forgets that one charge was also doubled, which should multiply by 2.", "misconception": "Ignoring the change in charge magnitude"}, {"option_key": "D", "hint": "F/3 uses neither the correct distance factor (should be 9, not 3) nor accounts for the charge doubling properly.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A charge Q is divided into two parts q and (Q − q). For the electrostatic force between them to be maximum when placed at a fixed distance, q should be:", "explanation": "Force F = kq(Q−q)/r² = k(qQ − q²)/r². For maximum F, dF/dq = 0 → Q − 2q = 0 → q = Q/2. So the force is maximum when the charge is divided equally. Second derivative d²F/dq² = −2k/r² < 0, confirming maximum.", "correct_answer": "C", "concept_tags": ["optimization", "coulomb-force", "maxima"], "payload": {"question_id": "cuet-phy-elec-coulomb-11", "subtopic": "Coulomb''s Law and Electric Charges", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "apply", "options": [{"key": "A", "text": "Q/4", "is_correct": false}, {"key": "B", "text": "Q/3", "is_correct": false}, {"key": "C", "text": "Q/2", "is_correct": true}, {"key": "D", "text": "Q", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "With q = Q/4, the product q(Q−q) = Q/4 × 3Q/4 = 3Q²/16 = 0.1875Q². This is less than the maximum possible value.", "misconception": null}, {"option_key": "B", "hint": "With q = Q/3, the product = Q/3 × 2Q/3 = 2Q²/9 ≈ 0.222Q², still less than the maximum of Q²/4 = 0.25Q².", "misconception": null}, {"option_key": "D", "hint": "If q = Q, then the other part is Q − Q = 0, giving zero force. This is actually the minimum, not maximum.", "misconception": "Not realizing that giving all charge to one part leaves nothing for the other"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Two point charges +4q and +q are placed at a distance L apart. The null point (where the net electric field is zero) lies:", "explanation": "The null point lies between the charges on the line joining them, closer to the smaller charge. Let it be at distance x from +q. At null point: kq/x² = k(4q)/(L−x)² → (L−x)² = 4x² → L−x = 2x → x = L/3. So the null point is at L/3 from +q (or 2L/3 from +4q).", "correct_answer": "B", "concept_tags": ["null-point", "electric-field", "superposition"], "payload": {"question_id": "cuet-phy-elec-coulomb-12", "subtopic": "Coulomb''s Law and Electric Charges", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "apply", "options": [{"key": "A", "text": "At L/2 from +4q (midpoint)", "is_correct": false}, {"key": "B", "text": "At L/3 from +q", "is_correct": true}, {"key": "C", "text": "At L/3 from +4q", "is_correct": false}, {"key": "D", "text": "Outside the charges, beyond +q", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The midpoint would only be the null point if both charges were equal. Since 4q > q, the null point shifts toward the weaker charge.", "misconception": "Assuming null point is always at the midpoint"}, {"option_key": "C", "hint": "L/3 from the larger charge (+4q) means 2L/3 from +q. At this point, the stronger charge is closer, making its field dominant — not a null point.", "misconception": "Placing the null point closer to the larger charge instead of the smaller"}, {"option_key": "D", "hint": "For two like charges, the null point always lies between them. It lies outside only when charges have opposite signs.", "misconception": "Confusing null point location for like vs unlike charges"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "If each of two point charges is doubled and the distance between them is halved, the electrostatic force between them becomes:", "explanation": "Original force: F = kq₁q₂/r². New force: F'' = k(2q₁)(2q₂)/(r/2)² = k × 4q₁q₂ / (r²/4) = 16 × kq₁q₂/r² = 16F. The force increases by a factor of 16.", "correct_answer": "C", "concept_tags": ["coulomb-law", "proportionality", "numerical"], "payload": {"question_id": "cuet-phy-elec-coulomb-13", "subtopic": "Coulomb''s law applications", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "apply", "options": [{"key": "A", "text": "4F", "is_correct": false}, {"key": "B", "text": "8F", "is_correct": false}, {"key": "C", "text": "16F", "is_correct": true}, {"key": "D", "text": "32F", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "4F accounts for doubling both charges (2×2=4) but ignores the effect of halving the distance, which adds another factor of 4.", "misconception": "Forgetting the distance factor"}, {"option_key": "B", "hint": "8F might come from 2×2×2=8, but halving distance gives 1/(1/2)²=4, not 2. Total should be 4×4=16.", "misconception": "Treating distance halving as a factor of 2 instead of 4"}, {"option_key": "D", "hint": "32F would require an extra factor of 2 beyond 16 — there''s no physical reason for this.", "misconception": null}]}}]'::jsonb, 'deploy-2026-03-05-b07');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The dielectric constant (relative permittivity) of a perfect conductor is:", "explanation": "Inside a perfect conductor, the electric field is always zero. Since K = E_vacuum/E_medium, for the field to be zero inside the conductor, K must be infinite. Alternatively, a conductor can be thought of as a medium that completely screens the electric field, requiring K → ∞.", "correct_answer": "D", "concept_tags": ["dielectric-constant", "conductor", "permittivity"], "payload": {"question_id": "cuet-phy-elec-coulomb-14", "subtopic": "Dielectrics and conductors", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "Zero", "is_correct": false}, {"key": "B", "text": "1", "is_correct": false}, {"key": "C", "text": "Negative", "is_correct": false}, {"key": "D", "text": "Infinity", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "K = 0 would mean ε = 0, which would imply infinite electric field inside the medium — the opposite of what happens in a conductor.", "misconception": "Confusing zero field inside conductor with zero dielectric constant"}, {"option_key": "B", "hint": "K = 1 corresponds to vacuum/air. A conductor has much stronger polarisation response than vacuum.", "misconception": "Thinking conductor behaves like vacuum"}, {"option_key": "C", "hint": "Dielectric constant is always positive. A negative value would imply the medium reverses the field direction, which doesn''t happen with normal conductors.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Two identical metallic spheres carrying charges of +40 μC and −10 μC are brought into contact and then separated. The charge on each sphere after separation is:", "explanation": "When two identical conducting spheres are brought into contact, the total charge distributes equally. Total charge = +40 + (−10) = +30 μC. Since the spheres are identical, each gets 30/2 = +15 μC after separation.", "correct_answer": "C", "concept_tags": ["charge-sharing", "conservation-of-charge", "conductors"], "payload": {"question_id": "cuet-phy-elec-coulomb-15", "subtopic": "Coulomb''s Law and Electric Charges", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "apply", "options": [{"key": "A", "text": "+20 μC", "is_correct": false}, {"key": "B", "text": "+25 μC", "is_correct": false}, {"key": "C", "text": "+15 μC", "is_correct": true}, {"key": "D", "text": "+30 μC", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "+20 μC would mean the average of absolute values (40+10)/2, ignoring that charges are algebraically added (signs matter).", "misconception": "Averaging absolute values instead of algebraic sum"}, {"option_key": "B", "hint": "+25 μC each would give a total of +50 μC, violating charge conservation (total is only +30 μC).", "misconception": null}, {"option_key": "D", "hint": "+30 μC on each sphere would give a total of +60 μC, double the actual total charge — charge is not doubled upon contact.", "misconception": "Forgetting to divide the total equally"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "When a glass rod is rubbed with silk, the rod becomes positively charged because:", "explanation": "During rubbing, electrons (not protons) are transferred from the glass rod to the silk. The rod loses electrons and becomes positively charged, while the silk gains those electrons and becomes negatively charged. Protons, being bound in the nucleus, do not transfer.", "correct_answer": "A", "concept_tags": ["charging-by-friction", "electron-transfer", "triboelectric"], "payload": {"question_id": "cuet-phy-elec-coulomb-16", "subtopic": "Methods of charging", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "Electrons are transferred from the rod to the silk", "is_correct": true}, {"key": "B", "text": "Protons are transferred from the silk to the rod", "is_correct": false}, {"key": "C", "text": "Protons are created on the rod", "is_correct": false}, {"key": "D", "text": "Neutrons are removed from the rod", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Protons are tightly bound in the nucleus and cannot be transferred by rubbing. Only electrons, which are in outer shells, can move.", "misconception": "Thinking protons can be transferred between materials"}, {"option_key": "C", "hint": "Charge is conserved — it cannot be created or destroyed. Rubbing only transfers existing charges.", "misconception": "Thinking charge can be created from nothing"}, {"option_key": "D", "hint": "Neutrons carry no charge, so removing them would not make the rod positively charged.", "misconception": "Confusing the role of neutrons in charge"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "Two identical small conducting spheres have charges +3Q and −Q. They are first touched together and then separated by a distance d. The force between them after separation, compared to the initial force (at the same distance d), is:", "explanation": "Initial force: F₁ = k(3Q)(Q)/d² = 3kQ²/d² (attractive). After touching: total charge = 3Q + (−Q) = 2Q, shared equally → each gets +Q. New force: F₂ = k(Q)(Q)/d² = kQ²/d² (repulsive). Ratio: F₂/F₁ = 1/3. Also, the force changed from attractive to repulsive.", "correct_answer": "D", "concept_tags": ["charge-sharing", "force-comparison", "attraction-repulsion"], "payload": {"question_id": "cuet-phy-elec-coulomb-17", "subtopic": "Coulomb''s Law and Electric Charges", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "analyze", "options": [{"key": "A", "text": "Same magnitude and same nature", "is_correct": false}, {"key": "B", "text": "1/3 of initial magnitude and same nature (attractive)", "is_correct": false}, {"key": "C", "text": "3 times the initial magnitude and repulsive", "is_correct": false}, {"key": "D", "text": "1/3 of initial magnitude and opposite nature (now repulsive)", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "The charges change from (+3Q, −Q) to (+Q, +Q). Both the product of charges and the sign change, so the force cannot remain the same.", "misconception": "Thinking charge sharing doesn''t affect the force"}, {"option_key": "B", "hint": "The magnitude ratio (1/3) is correct, but the nature changes — initially opposite charges (attractive) become same charges (repulsive) after contact.", "misconception": "Calculating magnitude correctly but forgetting to check if nature changes"}, {"option_key": "C", "hint": "Q²/d² is 1/3 of 3Q²/d², not 3 times. The force decreases, it doesn''t triple.", "misconception": "Inverting the ratio"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "Eight identical point charges q are placed at the eight corners of a cube of side a. The electrostatic force on any one charge due to the remaining seven is:", "explanation": "Consider one corner charge. The 7 other charges are at distances: 3 face-diagonal neighbours at a√2, 3 edge neighbours at a, and 1 body-diagonal neighbour at a√3. By symmetry, the net force on the corner charge is directed along the body diagonal (away from the cube centre). The magnitude requires vector addition of all 7 forces along this direction using direction cosines.", "correct_answer": "C", "concept_tags": ["cube-symmetry", "superposition", "three-dimensions"], "payload": {"question_id": "cuet-phy-elec-coulomb-18", "subtopic": "Coulomb''s Law and Electric Charges", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "analyze", "options": [{"key": "A", "text": "7kq²/a² directed toward the centre", "is_correct": false}, {"key": "B", "text": "Zero, by symmetry", "is_correct": false}, {"key": "C", "text": "Directed along the body diagonal, away from the centre", "is_correct": true}, {"key": "D", "text": "Directed along the edge of the cube", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The charges are all positive (like charges), so they repel — the force must be away from the cube, not toward the centre.", "misconception": "Getting the direction wrong for repulsive forces"}, {"option_key": "B", "hint": "The corner charge is NOT at the centre of the arrangement. The 7 other charges are NOT symmetrically distributed around a corner — there are more charges on one side.", "misconception": "Incorrectly applying symmetry — symmetry only gives zero at the centre"}, {"option_key": "D", "hint": "The cubic symmetry at a corner has three-fold symmetry about the body diagonal, so the net force must lie along this diagonal, not along any single edge.", "misconception": "Not recognising the 3-fold rotational symmetry about the body diagonal"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "A charge Q is uniformly distributed along a semi-circular arc of radius R. The magnitude of the electric field at the centre of curvature is:", "explanation": "Linear charge density λ = Q/(πR). Consider a small element dθ at angle θ from the axis of symmetry. Its field at centre: dE = kλRdθ/R² = kλdθ/R. By symmetry, only the component along the axis of symmetry (perpendicular bisector of the diameter) survives. E = ∫₀^π (kλ/R)sinθ dθ = (kλ/R)[-cosθ]₀^π = 2kλ/R = 2k(Q/πR)/R = 2kQ/(πR²).", "correct_answer": "C", "concept_tags": ["continuous-distribution", "semi-circular-arc", "integration"], "payload": {"question_id": "cuet-phy-elec-coulomb-19", "subtopic": "Continuous charge distributions", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "analyze", "options": [{"key": "A", "text": "kQ/R²", "is_correct": false}, {"key": "B", "text": "kQ/(πR²)", "is_correct": false}, {"key": "C", "text": "2kQ/(πR²)", "is_correct": true}, {"key": "D", "text": "Zero", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "kQ/R² treats the entire semi-circular charge as a point charge at distance R, ignoring the angular distribution.", "misconception": "Treating distributed charge as a point charge"}, {"option_key": "B", "hint": "kQ/(πR²) is missing the factor of 2 that comes from the integration of sinθ over 0 to π: ∫sinθ dθ = 2.", "misconception": "Integration error — forgetting the factor of 2"}, {"option_key": "D", "hint": "Zero would be the field at the centre of a full circle, not a semi-circle. The semi-circle has a net field along its symmetry axis.", "misconception": "Confusing semi-circular arc with full circular arc"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "Two isolated conducting spheres of radii R and 2R carry charges Q and 2Q respectively. They are connected by a thin conducting wire and then disconnected. The charge on the smaller sphere after disconnection is:", "explanation": "When connected, charge flows until both spheres reach the same potential. Total charge = Q + 2Q = 3Q. At equal potential: V₁ = V₂ → kq₁/R = kq₂/(2R) → q₂ = 2q₁. With q₁ + q₂ = 3Q: q₁ + 2q₁ = 3Q → q₁ = Q. The smaller sphere ends up with charge Q (same as its original charge, coincidentally).", "correct_answer": "A", "concept_tags": ["conducting-spheres", "charge-sharing", "equal-potential"], "payload": {"question_id": "cuet-phy-elec-coulomb-20", "subtopic": "Charge redistribution between conductors", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "analyze", "options": [{"key": "A", "text": "Q", "is_correct": true}, {"key": "B", "text": "3Q/2", "is_correct": false}, {"key": "C", "text": "2Q", "is_correct": false}, {"key": "D", "text": "Q/2", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "3Q/2 assumes equal charge on each sphere, but connected conductors equalise potential, not charge. Charge distributes proportional to radius.", "misconception": "Assuming equal charge instead of equal potential"}, {"option_key": "C", "hint": "2Q on the smaller sphere would leave Q on the larger, giving V_small/V_large = (2Q/R)/(Q/2R) = 4, violating equal potential.", "misconception": null}, {"option_key": "D", "hint": "Q/2 on smaller means 5Q/2 on larger. V_small/V_large = (Q/2R)/(5Q/4R) = 2/5, not equal.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "easy", "question_text": "The diagram shows four arrangements of two charges. In which arrangement is the electrostatic force between the charges repulsive?\n\n(A) +q ←→ −q\n(B) +q ←→ +q\n(C) −q ←→ +q\n(D) −q ←→ −2q (with one charge having larger magnitude)", "explanation": "Repulsive force occurs between like charges. Arrangement B (+q and +q) has two positive charges — they repel. Arrangement D (−q and −2q) also has like charges (both negative) — they also repel. But among the options, B is the straightforward like-charge case. Arrangements A and C have unlike charges and attract.", "correct_answer": "B", "concept_tags": ["like-charges", "repulsion", "attraction"], "payload": {"question_id": "cuet-phy-elec-coulomb-21", "subtopic": "Nature of electrostatic force", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "Arrangement A only", "is_correct": false}, {"key": "B", "text": "Arrangements B and D", "is_correct": true}, {"key": "C", "text": "Arrangement C only", "is_correct": false}, {"key": "D", "text": "All four arrangements", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Arrangement A has +q and −q (unlike charges) — they attract, not repel.", "misconception": "Confusing attraction with repulsion for unlike charges"}, {"option_key": "C", "hint": "Arrangement C has −q and +q (unlike charges) — this is identical in nature to A, both attract.", "misconception": "Not recognising that the order doesn''t matter — unlike charges always attract"}, {"option_key": "D", "hint": "Arrangements A and C have unlike charges, which attract — not all four are repulsive.", "misconception": "Thinking all charged bodies repel"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "medium", "question_text": "The diagram shows a graph of electrostatic force F versus distance r between two point charges. Which curve correctly represents Coulomb''s law?\n\nCurve P: F decreases linearly with r\nCurve Q: F decreases as 1/r²  (hyperbolic)\nCurve R: F decreases as 1/r (slower hyperbola)\nCurve S: F remains constant", "explanation": "Coulomb''s law states F = kq₁q₂/r², so F ∝ 1/r². This is represented by Curve Q — a steep hyperbolic decay. At small r, the force is very large; it drops rapidly and approaches zero at large r. The 1/r² curve is steeper than 1/r at small distances.", "correct_answer": "A", "concept_tags": ["inverse-square-law", "graphical-representation", "force-distance"], "payload": {"question_id": "cuet-phy-elec-coulomb-22", "subtopic": "Coulomb''s law graphical analysis", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "Curve Q", "is_correct": true}, {"key": "B", "text": "Curve P", "is_correct": false}, {"key": "C", "text": "Curve R", "is_correct": false}, {"key": "D", "text": "Curve S", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Curve P shows a linear decrease, meaning F ∝ (constant − r). Coulomb''s law is not linear — it''s inverse square.", "misconception": "Thinking force decreases linearly with distance"}, {"option_key": "C", "hint": "Curve R (1/r) represents electric potential V = kq/r, not force. Force falls faster (as 1/r²).", "misconception": "Confusing force (1/r²) with potential (1/r)"}, {"option_key": "D", "hint": "Curve S (constant force) would mean force doesn''t depend on distance, contradicting Coulomb''s law completely.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "medium", "question_text": "The figure shows four charges placed at the corners of a square of side a: +q at A (top-left), +q at B (top-right), −q at C (bottom-right), −q at D (bottom-left). What is the direction of the net force on the charge at A?", "explanation": "Forces on +q at A: From +q at B (distance a, repulsive → pushes A leftward). From −q at C (distance a√2, attractive → pulls A toward C, i.e., diagonally toward bottom-right). From −q at D (distance a, attractive → pulls A downward). The leftward push from B and downward pull from D combine. Adding the diagonal pull toward C, the net force points approximately toward D (downward and slightly right), i.e., parallel to the side AD directed downward.", "correct_answer": "C", "concept_tags": ["vector-addition", "square-configuration", "net-force"], "payload": {"question_id": "cuet-phy-elec-coulomb-23", "subtopic": "Superposition of forces", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "analyze", "options": [{"key": "A", "text": "Horizontally toward B", "is_correct": false}, {"key": "B", "text": "Along the diagonal AC, toward C", "is_correct": false}, {"key": "C", "text": "Parallel to AD, directed from A toward D", "is_correct": true}, {"key": "D", "text": "Zero — forces cancel by symmetry", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The force from +q at B is repulsive (pushes A away from B, i.e., leftward), not toward B.", "misconception": "Confusing attraction and repulsion directions"}, {"option_key": "B", "hint": "While there is a component toward C, the forces from B and D also contribute. The net direction is along AD, not along the diagonal.", "misconception": "Considering only the diagonal force and ignoring edge forces"}, {"option_key": "D", "hint": "The configuration is NOT symmetric about charge A — there''s +q on one side and −q on the other. Forces don''t cancel.", "misconception": "Incorrectly assuming symmetry at a corner of a non-uniform charge distribution"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "hard", "question_text": "The figure shows a log-log plot (log F vs log r) for the electrostatic force between two point charges. The graph is a straight line with slope −2 and y-intercept log(kq₁q₂). If the experimental data shows a slope of −2.05 ± 0.03, what can be concluded?", "explanation": "Taking log of F = kq₁q₂/rⁿ gives log F = log(kq₁q₂) − n × log r. A log-log plot gives a straight line with slope −n. The theoretical value is n = 2 (inverse square law). The experimental slope of −2.05 ± 0.03 includes n = 2 within the error range (2.05 − 0.03 = 2.02 and 2.05 + 0.03 = 2.08), so the data is consistent with the inverse square law within experimental uncertainty.", "correct_answer": "D", "concept_tags": ["log-log-plot", "experimental-verification", "inverse-square"], "payload": {"question_id": "cuet-phy-elec-coulomb-24", "subtopic": "Experimental verification of Coulomb''s law", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "analyze", "options": [{"key": "A", "text": "Coulomb''s law is definitively disproved", "is_correct": false}, {"key": "B", "text": "The force follows an inverse cube law", "is_correct": false}, {"key": "C", "text": "The experiment has no errors", "is_correct": false}, {"key": "D", "text": "The data is consistent with Coulomb''s inverse square law within experimental uncertainty", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "A slope of −2.05 ± 0.03 is very close to −2 and includes −2 within 2σ. Experimental uncertainty must be considered before claiming a law is disproved.", "misconception": "Ignoring experimental uncertainty when comparing with theory"}, {"option_key": "B", "hint": "An inverse cube law would give slope −3, which is far outside the measured range of −2.05 ± 0.03.", "misconception": "Confusing the measured slope with a completely different power law"}, {"option_key": "C", "hint": "Every experiment has some uncertainty. The ±0.03 explicitly states the error range.", "misconception": "Thinking a small deviation means zero error rather than acknowledging uncertainty"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): A charged body can attract an uncharged body.\nReason (R): When a charged body is brought near an uncharged body, it induces opposite charge on the nearer surface of the uncharged body.", "explanation": "The assertion is true — a charged body (say positively charged) brought near an uncharged conductor induces negative charge on the nearer surface and positive charge on the far surface. The attractive force on the nearer induced charge is stronger than the repulsive force on the farther induced charge (since force ∝ 1/r²). So there is a net attraction. The reason correctly explains this mechanism. Both A and R are true, and R is the correct explanation of A.", "correct_answer": "A", "concept_tags": ["induction", "attraction-uncharged-body"], "payload": {"question_id": "cuet-phy-elec-coulomb-25", "subtopic": "Coulomb''s Law and Electric Charges", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The induced opposite charge on the nearer surface is precisely the mechanism that causes attraction — R directly explains A.", "misconception": "Thinking the reason is unrelated to the assertion"}, {"option_key": "C", "hint": "The reason is factually correct — induction does create opposite charges on the nearer surface. This is a well-established phenomenon.", "misconception": "Doubting the mechanism of electrostatic induction"}, {"option_key": "D", "hint": "The assertion is definitely correct — it''s a commonly observed phenomenon. Rub a comb on hair and it attracts paper bits (which are uncharged).", "misconception": "Thinking only charged bodies can be attracted"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): A sensitive gold-leaf electroscope can detect charge quantization at macroscopic scales.\nReason (R): The elementary charge e = 1.6 × 10⁻¹⁹ C is extremely small compared to charges typically encountered in daily life.", "explanation": "A is FALSE: at macroscopic scales, charges are so large (of order μC or more) that the discrete nature (quantization) of charge is not observable — charge appears continuous. R is TRUE: e is indeed extremely small compared to macroscopic charges, which is precisely why quantization is undetectable at large scales. Since A is incorrect and R is correct, the answer is D.", "correct_answer": "D", "concept_tags": ["quantization", "macroscopic-charge", "gold-leaf-electroscope"], "payload": {"question_id": "cuet-phy-elec-coulomb-26", "subtopic": "Quantization of charge", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "The assertion is incorrect — quantization cannot be detected at macroscopic scales because the elementary charge is too small relative to everyday charges.", "misconception": "Thinking quantization is easily observable with a gold-leaf electroscope"}, {"option_key": "B", "hint": "A is false, not true. A gold-leaf electroscope cannot detect individual electron charges.", "misconception": null}, {"option_key": "C", "hint": "R is actually correct — e = 1.6 × 10⁻¹⁹ C is indeed extremely small compared to typical macroscopic charges.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): Coulomb''s law and Newton''s law of gravitation have the same mathematical form (inverse square law), but the electrostatic force can be both attractive and repulsive.\nReason (R): Electric charge comes in two types (positive and negative) whereas mass is always positive.", "explanation": "Assertion is true: both F = kq₁q₂/r² and F = Gm₁m₂/r² follow the inverse square law, but gravity is always attractive while electrostatic force can be attractive (unlike charges) or repulsive (like charges). Reason is also true: the existence of two types of charge (+ and −) allows for both attraction and repulsion, while mass being always positive means gravity can only be attractive. R correctly explains why electrostatic force has dual nature while gravity doesn''t.", "correct_answer": "A", "concept_tags": ["coulomb-vs-gravity", "charge-types", "force-nature"], "payload": {"question_id": "cuet-phy-elec-coulomb-27", "subtopic": "Coulomb''s Law and Electric Charges", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The existence of two charge types is exactly what causes the electrostatic force to be either attractive or repulsive — R directly explains the dual nature mentioned in A.", "misconception": "Missing the causal connection between charge duality and force nature"}, {"option_key": "C", "hint": "The reason is factually correct — charge has two types (positive and negative) while mass is always positive. This is basic physics.", "misconception": null}, {"option_key": "D", "hint": "The assertion is factually correct — both laws follow inverse square dependence, and electrostatic force can be attractive or repulsive unlike gravity.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): Coulomb''s law accurately predicts the force between two charged bodies of any shape and size.\nReason (R): Coulomb''s law is derived for point charges and works accurately only when the size of the charged bodies is much smaller than the distance between them.", "explanation": "A is FALSE: Coulomb''s law in its standard form F = kq₁q₂/r² is strictly valid only for point charges (or when bodies are very small compared to separation). For extended bodies, charge distribution matters and the simple formula is inadequate. R is TRUE: it correctly states the limitation. Since A is wrong and R is right, the answer is D.", "correct_answer": "D", "concept_tags": ["coulomb-law-limitations", "point-charge-approximation"], "payload": {"question_id": "cuet-phy-elec-coulomb-28", "subtopic": "Validity conditions of Coulomb''s law", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "A is false — Coulomb''s law does not work for bodies of any shape/size. For large or close conductors, charge redistribution invalidates the point-charge formula.", "misconception": "Thinking Coulomb''s law applies universally to all shapes"}, {"option_key": "B", "hint": "A is false, so this option cannot be correct.", "misconception": null}, {"option_key": "C", "hint": "R is factually correct — it accurately describes the point-charge requirement of Coulomb''s law.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match the charging method in Column I with its key characteristic in Column II:\n\nColumn I:\nA. Charging by friction\nB. Charging by conduction\nC. Charging by induction\nD. Charging by a Van de Graaff generator\n\nColumn II:\n1. Charge accumulation on a hollow sphere using a belt\n2. Both bodies acquire equal and opposite charges\n3. The charged body transfers charge to the uncharged body on contact\n4. The charged body induces charge separation without contact", "explanation": "Friction (A) involves rubbing two bodies — both acquire equal and opposite charges → A-2. Conduction (B) involves touching a charged body to an uncharged one — charge flows on contact → B-3. Induction (C) involves bringing a charged body near an uncharged conductor without contact → C-4. Van de Graaff generator (D) uses a moving belt to accumulate charge on a hollow metal sphere → D-1.", "correct_answer": "C", "concept_tags": ["charging-methods", "friction", "conduction", "induction"], "payload": {"question_id": "cuet-phy-elec-coulomb-29", "subtopic": "Methods of charging", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "A-3, B-2, C-4, D-1", "is_correct": false}, {"key": "B", "text": "A-2, B-4, C-3, D-1", "is_correct": false}, {"key": "C", "text": "A-2, B-3, C-4, D-1", "is_correct": true}, {"key": "D", "text": "A-4, B-3, C-2, D-1", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This assigns ''charge transfer on contact'' (3) to friction and ''equal and opposite charges'' (2) to conduction. In friction, both bodies get equal opposite charges; conduction involves contact transfer.", "misconception": "Swapping friction and conduction characteristics"}, {"option_key": "B", "hint": "This assigns ''no contact'' (4) to conduction, but conduction requires physical contact.", "misconception": "Confusing conduction (contact required) with induction (no contact)"}, {"option_key": "D", "hint": "This assigns ''no contact'' (4) to friction, but friction requires vigorous rubbing (contact).", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "hard", "question_text": "Match the physical situation in Column I with the correct force expression in Column II:\n\nColumn I:\nA. Two charges q in vacuum at distance d\nB. Two charges q in medium (K=4) at distance d\nC. Two charges q in vacuum at distance 2d\nD. Charges 2q and q in vacuum at distance d\n\nColumn II:\n1. kq²/(4d²)\n2. 2kq²/d²\n3. kq²/(4d²)\n4. kq²/d²", "explanation": "A: F = kq²/d² → A-4. B: F = kq²/(Kd²) = kq²/(4d²) → B-1 (or B-3, since items 1 and 3 are identical). C: F = kq²/(2d)² = kq²/(4d²) → C-3 (or C-1). D: F = k(2q)(q)/d² = 2kq²/d² → D-2. Note: items 1 and 3 have the same expression, so B and C both map to kq²/(4d²).", "correct_answer": "B", "concept_tags": ["coulomb-law-variations", "dielectric", "distance-scaling"], "payload": {"question_id": "cuet-phy-elec-coulomb-30", "subtopic": "Coulomb''s law applications", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "apply", "options": [{"key": "A", "text": "A-4, B-2, C-1, D-3", "is_correct": false}, {"key": "B", "text": "A-4, B-1, C-3, D-2", "is_correct": true}, {"key": "C", "text": "A-2, B-4, C-3, D-1", "is_correct": false}, {"key": "D", "text": "A-4, B-3, C-2, D-1", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This assigns 2kq²/d² to situation B (medium K=4), but a medium reduces the force, so B cannot give the largest force expression.", "misconception": "Thinking a dielectric increases the force"}, {"option_key": "C", "hint": "This assigns kq²/d² (full vacuum force) to two charges q in vacuum at 2d — but doubling distance reduces force by 4.", "misconception": "Ignoring the effect of doubling the distance"}, {"option_key": "D", "hint": "This maps D (charges 2q and q) to kq²/(4d²), but the product 2q×q = 2q² gives 2kq²/d², not kq²/4d².", "misconception": "Not computing the charge product correctly"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The total charge of an isolated system is always conserved, regardless of the interactions within the system.", "explanation": "This is TRUE. Conservation of charge is a fundamental law of physics. In any isolated system, the total electric charge remains constant — charges can be transferred, redistributed, or created in pairs (particle-antiparticle), but the algebraic sum never changes. This has been verified in countless experiments and is as fundamental as conservation of energy.", "correct_answer": "A", "concept_tags": ["conservation-of-charge", "fundamental-law"], "payload": {"question_id": "cuet-phy-elec-coulomb-31", "subtopic": "Coulomb''s Law and Electric Charges", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Conservation of charge is one of the most rigorously tested laws in physics. No experiment has ever found a violation.", "misconception": "Thinking charge conservation can be violated in nuclear reactions or pair production"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "Electric charge is an additive quantity — the total charge of a system is the algebraic sum of all individual charges.", "explanation": "This is TRUE. Additivity of charge means the total charge of a system equals the algebraic (not absolute) sum of all charges. For example, if a system has charges +5 μC and −3 μC, the total charge is +2 μC. This property, along with conservation and quantization, is a fundamental property of electric charge.", "correct_answer": "A", "concept_tags": ["additivity", "charge-properties", "algebraic-sum"], "payload": {"question_id": "cuet-phy-elec-coulomb-32", "subtopic": "Properties of electric charge", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Additivity of charge is a well-established property. Unlike some quantities (like mass in relativity), charge adds algebraically in all situations.", "misconception": "Confusing additivity of charge with non-additive quantities"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "Coulomb''s law can be applied directly to calculate the force between two charged conducting spheres of finite radius placed close together.", "explanation": "This is FALSE. Coulomb''s law in its standard form F = kq₁q₂/r² applies to point charges. For conducting spheres placed close together, the charge distribution on each sphere gets distorted (induced redistribution) — it is no longer uniform. The charges concentrate on the nearer surfaces (for opposite charges) or redistribute unevenly. To find the exact force, one must account for this non-uniform distribution, not simply use Coulomb''s law with centre-to-centre distance.", "correct_answer": "B", "concept_tags": ["coulomb-law-limitations", "finite-size-effects"], "payload": {"question_id": "cuet-phy-elec-coulomb-33", "subtopic": "Coulomb''s Law and Electric Charges", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Coulomb''s law assumes point charges. For finite-sized conductors placed close together, charge redistribution occurs on the surfaces, making the point-charge approximation invalid.", "misconception": "Assuming Coulomb''s law works for all charge geometries without modification"}]}}]'::jsonb, 'deploy-2026-03-05-b07');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The force between two point charges depends on the nature of the medium between them — it decreases when a dielectric is placed between them but increases when they are in vacuum.", "explanation": "This is partially misleading but essentially FALSE as stated. The statement implies the force ''increases in vacuum'' as if vacuum makes it stronger than some baseline — but vacuum IS the reference (maximum force). The force in any medium is F/K where K ≥ 1. The statement''s implication that force ''increases'' in vacuum is incorrect framing. The correct statement: force is maximum in vacuum and decreases in any dielectric medium.", "correct_answer": "B", "concept_tags": ["dielectric-effect", "medium-dependence", "vacuum"], "payload": {"question_id": "cuet-phy-elec-coulomb-34", "subtopic": "Coulomb''s law in different media", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The phrasing ''increases in vacuum'' is misleading. Force is maximum in vacuum — it doesn''t ''increase'' because vacuum is already the reference state (K=1). Any medium only reduces the force.", "misconception": "Thinking vacuum actively increases the force rather than being the baseline"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "easy", "question_text": "The minimum charge that can exist independently in nature is called the _____ charge, and its value is approximately _____.", "explanation": "The minimum independently existing charge is the elementary charge (e), with value approximately 1.6 × 10⁻¹⁹ C. This was first accurately measured by Robert Millikan in his oil-drop experiment (1909). All observable charges are integral multiples of this fundamental unit.", "correct_answer": "D", "concept_tags": ["elementary-charge", "millikan-experiment"], "payload": {"question_id": "cuet-phy-elec-coulomb-35", "subtopic": "Quantization of charge", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "remember", "options": [{"key": "A", "text": "unit; 1 coulomb", "is_correct": false}, {"key": "B", "text": "fractional; 1.6 × 10⁻²⁰ C", "is_correct": false}, {"key": "C", "text": "atomic; 9.1 × 10⁻³¹ kg", "is_correct": false}, {"key": "D", "text": "elementary; 1.6 × 10⁻¹⁹ C", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "1 coulomb is a macroscopic unit of charge (≈6.25 × 10¹⁸ electron charges), far too large to be the minimum charge.", "misconception": "Confusing the SI unit with the fundamental minimum"}, {"option_key": "B", "hint": "1.6 × 10⁻²⁰ C is ten times smaller than the actual elementary charge. Also, charge is not called ''fractional charge''.", "misconception": "Incorrect value of elementary charge"}, {"option_key": "C", "hint": "9.1 × 10⁻³¹ kg is the mass of an electron, not a charge. The units are wrong (kg vs C).", "misconception": "Confusing electron mass with electron charge"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "fill-in-blanks", "difficulty": "medium", "question_text": "The charge on a body is always an integral multiple of _____, which is known as the quantization of electric charge.", "explanation": "The quantization of electric charge states that the charge on any body is always q = ne, where n is an integer and e = 1.6 × 10⁻¹⁹ C is the elementary charge. This means charge cannot exist in fractions of e (in free state). Robert Millikan''s oil drop experiment provided the first precise measurement of e.", "correct_answer": "D", "concept_tags": ["quantization", "elementary-charge", "millikan"], "payload": {"question_id": "cuet-phy-elec-coulomb-36", "subtopic": "Coulomb''s Law and Electric Charges", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "remember", "options": [{"key": "A", "text": "1 coulomb", "is_correct": false}, {"key": "B", "text": "1 ampere-second", "is_correct": false}, {"key": "C", "text": "1.6 × 10⁻²⁰ C", "is_correct": false}, {"key": "D", "text": "1.6 × 10⁻¹⁹ C (the elementary charge e)", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "1 coulomb is far too large to be the quantum of charge — it contains ~6.25 × 10¹⁸ elementary charges.", "misconception": "Confusing the SI unit with the fundamental quantum"}, {"option_key": "B", "hint": "While 1 ampere-second equals 1 coulomb dimensionally, this is the same as option A — it''s the SI unit, not the quantum.", "misconception": null}, {"option_key": "C", "hint": "The correct value is 1.6 × 10⁻¹⁹ C, not 10⁻²⁰. This is one order of magnitude too small.", "misconception": "Error in the exponent"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "medium", "question_text": "In a laboratory experiment, a student uses a Coulomb''s torsion balance to measure the force between two charged pith balls. When the distance between the balls is halved (keeping charges the same), the student observes that the torsion angle quadruples. However, when the student inserts a glass slab (dielectric constant K = 5) between the two balls at the original distance, the torsion angle becomes 1/5th of the original. Based on these observations, which conclusion is correct?", "explanation": "When distance is halved: F'' = kq₁q₂/(d/2)² = 4kq₁q₂/d² = 4F. The force quadruples, so the torsion angle quadruples — consistent with inverse square law. When a dielectric (K = 5) is inserted: F'''' = kq₁q₂/(Kd²) = F/5. The force becomes 1/5th — consistent with the dielectric reducing the force by factor K. Both observations confirm Coulomb''s law: inverse square dependence on distance and linear dependence on dielectric constant.", "correct_answer": "B", "concept_tags": ["coulomb-torsion-balance", "inverse-square", "dielectric"], "payload": {"question_id": "cuet-phy-elec-coulomb-37", "subtopic": "Coulomb''s Law and Electric Charges", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "analyze", "options": [{"key": "A", "text": "Only the inverse square law is verified; the dielectric result is anomalous", "is_correct": false}, {"key": "B", "text": "Both observations are consistent with Coulomb''s law — F ∝ 1/r² and F ∝ 1/K", "is_correct": true}, {"key": "C", "text": "The dielectric should have increased the force, not decreased it", "is_correct": false}, {"key": "D", "text": "The force should have become 1/25th with the dielectric, not 1/5th", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The dielectric result (F/K) is a standard prediction of Coulomb''s law — it is not anomalous but expected.", "misconception": "Not knowing how dielectrics affect Coulomb''s law"}, {"option_key": "C", "hint": "Dielectrics always reduce electrostatic force between charges. The polarised medium partially screens the charges, weakening the interaction.", "misconception": "Confusing the effect of a dielectric — it reduces, not increases, the force"}, {"option_key": "D", "hint": "1/25 would mean dividing by K² = 25, but Coulomb''s law divides by K (first power), not K².", "misconception": "Incorrectly squaring the dielectric constant K"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "scenario-based", "difficulty": "hard", "question_text": "In an advanced electrostatics lab, two identical insulating spheres A and B carry charges +6Q and −2Q respectively. They are touched together, separated, and then sphere B is touched to an identical uncharged sphere C. After all separations, the charges on A, B, and C respectively are:", "explanation": "Step 1: A (+6Q) and B (−2Q) touch → total = 4Q, each gets +2Q. After separation: A = +2Q, B = +2Q. Step 2: B (+2Q) touches C (0) → total = 2Q, each gets +Q. After separation: B = +Q, C = +Q. Final: A = +2Q, B = +Q, C = +Q.", "correct_answer": "D", "concept_tags": ["charge-sharing", "multiple-steps", "conductors"], "payload": {"question_id": "cuet-phy-elec-coulomb-38", "subtopic": "Charge redistribution", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "analyze", "options": [{"key": "A", "text": "+2Q, +2Q, 0", "is_correct": false}, {"key": "B", "text": "+3Q, +Q/2, +Q/2", "is_correct": false}, {"key": "C", "text": "+4Q/3, +4Q/3, +4Q/3", "is_correct": false}, {"key": "D", "text": "+2Q, +Q, +Q", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "This only accounts for step 1 (A and B sharing charge) but ignores step 2 (B touching C).", "misconception": "Forgetting the second touching step"}, {"option_key": "B", "hint": "+3Q total ≠ 4Q total. The total charge must be conserved at +6Q + (−2Q) = +4Q throughout.", "misconception": "Arithmetic error in charge conservation"}, {"option_key": "C", "hint": "This assumes all three spheres share charge equally, but A was separated before B touched C. A doesn''t participate in the second sharing.", "misconception": "Assuming all three spheres share charge simultaneously"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "medium", "question_text": "Arrange the following steps of charging a metal sphere by induction in the correct sequence:\n\n1. Ground the sphere (connect to earth)\n2. Bring a positively charged rod near the sphere (without touching)\n3. Remove the grounding connection\n4. Remove the charged rod\n5. Negative charge remains on the sphere", "explanation": "Correct sequence: First bring the charged rod near (2) → this induces charge separation. Then ground the sphere (1) → positive charges flow to earth, leaving excess negative. Remove ground (3) → excess negative charge is trapped. Remove the rod (4) → negative charge redistributes uniformly. Result: sphere is negatively charged (5).", "correct_answer": "C", "concept_tags": ["induction-charging", "sequence", "grounding"], "payload": {"question_id": "cuet-phy-elec-coulomb-39", "subtopic": "Charging by induction", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "understand", "options": [{"key": "A", "text": "1 → 2 → 3 → 4 → 5", "is_correct": false}, {"key": "B", "text": "2 → 3 → 1 → 4 → 5", "is_correct": false}, {"key": "C", "text": "2 → 1 → 3 → 4 → 5", "is_correct": true}, {"key": "D", "text": "1 → 2 → 4 → 3 → 5", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Grounding first (step 1) without the charged rod nearby has no effect — there''s no induced charge to drain. The rod must be brought close first.", "misconception": "Grounding before bringing the inducing charge"}, {"option_key": "B", "hint": "Removing ground (step 3) before connecting it (step 1) is illogical. You must ground first, then remove the ground.", "misconception": "Mixing up the order of grounding and ungrounding"}, {"option_key": "D", "hint": "Removing the rod (step 4) before removing the ground (step 3) would allow the trapped negative charge to flow back to earth, leaving the sphere uncharged.", "misconception": "Not realising that the ground must be removed BEFORE the rod"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-coulomb", "exam_ids": ["CUET", "NEET"], "question_type": "logical-sequence", "difficulty": "hard", "question_text": "Arrange the following discoveries/developments in the history of electrostatics in chronological order:\n\n1. Millikan''s oil drop experiment (precise measurement of e)\n2. Coulomb''s torsion balance experiment\n3. Benjamin Franklin''s kite experiment\n4. Discovery of the electron by J.J. Thomson", "explanation": "Chronological order: Benjamin Franklin''s kite experiment (1752) → Coulomb''s torsion balance (1785) → J.J. Thomson discovers the electron (1897) → Millikan''s oil drop experiment (1909). So the sequence is 3 → 2 → 4 → 1.", "correct_answer": "B", "concept_tags": ["history-of-physics", "chronological-order", "electrostatics"], "payload": {"question_id": "cuet-phy-elec-coulomb-40", "subtopic": "Historical development", "topic_name": "Coulomb''s Law and Electric Charges", "bloom_level": "remember", "options": [{"key": "A", "text": "2 → 3 → 4 → 1", "is_correct": false}, {"key": "B", "text": "3 → 2 → 4 → 1", "is_correct": true}, {"key": "C", "text": "3 → 2 → 1 → 4", "is_correct": false}, {"key": "D", "text": "1 → 4 → 2 → 3", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Coulomb''s experiment (1785) came after Franklin''s (1752), not before. Franklin predated Coulomb by about 33 years.", "misconception": "Placing Coulomb before Franklin"}, {"option_key": "C", "hint": "Millikan (1909) came after Thomson (1897), not before. Millikan measured the charge of the electron that Thomson had discovered.", "misconception": "Thinking Millikan''s experiment preceded Thomson''s discovery of the electron"}, {"option_key": "D", "hint": "This puts the most recent (Millikan, 1909) first and the earliest (Franklin, 1752) last — completely reversed chronology.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The electric field at a point is defined as:", "explanation": "Electric field E at a point is defined as the force F experienced by a unit positive test charge q₀ placed at that point: E = F/q₀. The test charge must be vanishingly small so it doesn''t disturb the source charge distribution. The field is a vector quantity with SI unit N/C or V/m.", "correct_answer": "B", "concept_tags": ["electric-field-definition", "test-charge", "vector"], "payload": {"question_id": "cuet-phy-elec-field-01", "subtopic": "Definition of electric field", "topic_name": "Electric Field and Field Lines", "bloom_level": "remember", "options": [{"key": "A", "text": "Force experienced by any charge at that point", "is_correct": false}, {"key": "B", "text": "Force per unit positive test charge at that point", "is_correct": true}, {"key": "C", "text": "Work done per unit charge", "is_correct": false}, {"key": "D", "text": "Charge per unit area", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The force depends on the magnitude of the test charge. The field is force per UNIT charge, making it independent of the test charge.", "misconception": "Confusing total force with field (force per unit charge)"}, {"option_key": "C", "hint": "Work done per unit charge is the definition of electric potential (V), not electric field (E).", "misconception": "Confusing electric field with electric potential"}, {"option_key": "D", "hint": "Charge per unit area is the definition of surface charge density (σ), not electric field.", "misconception": "Confusing electric field with charge density"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Electric field lines start from:", "explanation": "Electric field lines originate from positive charges and terminate on negative charges. They represent the direction of force that a positive test charge would experience. If there are no negative charges nearby, field lines extend to infinity.", "correct_answer": "A", "concept_tags": ["field-lines", "positive-charge", "negative-charge"], "payload": {"question_id": "cuet-phy-elec-field-02", "subtopic": "Properties of field lines", "topic_name": "Electric Field and Field Lines", "bloom_level": "remember", "options": [{"key": "A", "text": "Positive charges and end on negative charges", "is_correct": true}, {"key": "B", "text": "Negative charges and end on positive charges", "is_correct": false}, {"key": "C", "text": "Any charge and form closed loops", "is_correct": false}, {"key": "D", "text": "Regions of low field and end at regions of high field", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This is the reverse of the convention. Field lines indicate the direction a positive test charge would move — away from positive, toward negative.", "misconception": "Reversing the direction convention for field lines"}, {"option_key": "C", "hint": "Electrostatic field lines never form closed loops — that''s a property of magnetic field lines. Electric field is conservative.", "misconception": "Confusing electric field lines with magnetic field lines"}, {"option_key": "D", "hint": "Field lines originate and terminate on charges, not on regions of different field strength.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The SI unit of electric field intensity is equivalent to:", "explanation": "Electric field E = F/q has SI unit N/C (newton per coulomb). Since work = force × distance, and potential V = W/q, we get V = Ed, so E = V/d, giving units V/m (volt per metre). Both N/C and V/m are equivalent and interchangeable.", "correct_answer": "C", "concept_tags": ["SI-units", "electric-field", "equivalence"], "payload": {"question_id": "cuet-phy-elec-field-03", "subtopic": "Units of electric field", "topic_name": "Electric Field and Field Lines", "bloom_level": "remember", "options": [{"key": "A", "text": "N/C only", "is_correct": false}, {"key": "B", "text": "V/m only", "is_correct": false}, {"key": "C", "text": "Both N/C and V/m", "is_correct": true}, {"key": "D", "text": "J/C", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "While N/C is correct, V/m is also a valid unit for electric field (E = −dV/dr). The question asks about equivalence.", "misconception": "Not knowing that N/C = V/m"}, {"option_key": "B", "hint": "V/m is correct but N/C is equally valid. E = F/q gives N/C directly.", "misconception": "Thinking only the potential-based unit is valid"}, {"option_key": "D", "hint": "J/C is the unit of electric potential (V), not electric field. E has an additional 1/m factor.", "misconception": "Confusing potential (J/C = V) with field (V/m)"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "Two electric field lines can never cross each other because:", "explanation": "If two field lines crossed, there would be two different directions of electric field at the crossing point, which is impossible — the electric field at any point has a unique direction. This is because the field is a well-defined vector function of position.", "correct_answer": "D", "concept_tags": ["field-lines-properties", "uniqueness", "vector-field"], "payload": {"question_id": "cuet-phy-elec-field-04", "subtopic": "Properties of field lines", "topic_name": "Electric Field and Field Lines", "bloom_level": "understand", "options": [{"key": "A", "text": "Field lines are always straight", "is_correct": false}, {"key": "B", "text": "Field lines carry energy", "is_correct": false}, {"key": "C", "text": "Charges would cancel at the crossing point", "is_correct": false}, {"key": "D", "text": "The electric field at a point must have a unique direction", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Field lines are NOT always straight — they curve around charge distributions. This is not the reason they can''t cross.", "misconception": "Thinking field lines are always straight"}, {"option_key": "B", "hint": "Whether field lines carry energy is irrelevant to why they can''t cross. The reason is about direction uniqueness.", "misconception": null}, {"option_key": "C", "hint": "Field lines don''t represent charges — they represent the direction and strength of the field. There''s no charge at a crossing point.", "misconception": "Confusing field lines with charges"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The electric field due to a point charge q at distance r from it varies as:", "explanation": "From Coulomb''s law, E = kq/r² = q/(4πε₀r²). The field follows an inverse square law — it decreases as the square of the distance from the charge. At twice the distance, the field is one-fourth.", "correct_answer": "A", "concept_tags": ["inverse-square", "point-charge-field", "distance-dependence"], "payload": {"question_id": "cuet-phy-elec-field-05", "subtopic": "Field due to a point charge", "topic_name": "Electric Field and Field Lines", "bloom_level": "remember", "options": [{"key": "A", "text": "1/r²", "is_correct": true}, {"key": "B", "text": "1/r", "is_correct": false}, {"key": "C", "text": "1/r³", "is_correct": false}, {"key": "D", "text": "r²", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "1/r dependence applies to the electric field of an infinitely long line charge, not a point charge.", "misconception": "Confusing point charge field with line charge field"}, {"option_key": "C", "hint": "1/r³ dependence applies to the electric field of a dipole at large distances, not a single point charge.", "misconception": "Confusing point charge field with dipole field"}, {"option_key": "D", "hint": "r² would mean the field increases with distance, which contradicts the fact that the field weakens as you move away from a charge.", "misconception": "Inverting the relationship — confusing direct with inverse"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "Two point charges +q and −q are placed at equal distances from a point P. The electric field at P is:", "explanation": "This depends on the geometry. If P is on the perpendicular bisector of the line joining the charges: the field components along the bisector cancel, and the net field points from +q toward −q (parallel to the line joining the charges). If P is on the line joining them between the charges: both fields point toward −q and add up. In general, the field is NOT zero because the fields from opposite charges don''t cancel (they point in the same general direction at most points).", "correct_answer": "B", "concept_tags": ["superposition", "opposite-charges", "field-direction"], "payload": {"question_id": "cuet-phy-elec-field-06", "subtopic": "Superposition of electric fields", "topic_name": "Electric Field and Field Lines", "bloom_level": "understand", "options": [{"key": "A", "text": "Always zero", "is_correct": false}, {"key": "B", "text": "Non-zero and depends on the position of P", "is_correct": true}, {"key": "C", "text": "Always directed perpendicular to the line joining the charges", "is_correct": false}, {"key": "D", "text": "Always equal to 2kq/r²", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The fields from +q and −q at most points do NOT cancel because they generally point in similar directions (both have a component toward −q).", "misconception": "Assuming equal and opposite charges always produce zero field everywhere"}, {"option_key": "C", "hint": "This is true only on the perpendicular bisector. At other points (e.g., on the line joining the charges), the field is along that line.", "misconception": "Overgeneralising a result valid only on the bisector"}, {"option_key": "D", "hint": "The field magnitude varies with position and direction relative to the charges. 2kq/r² is not a universal expression.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The electric field at the midpoint of two equal positive charges +Q separated by distance 2d is:", "explanation": "At the midpoint, each charge is at distance d. The field from the left charge points rightward (away from +Q), and the field from the right charge points leftward (away from +Q). Both have equal magnitude kQ/d². Since they point in opposite directions, they cancel: E_net = 0.", "correct_answer": "C", "concept_tags": ["midpoint-field", "like-charges", "cancellation"], "payload": {"question_id": "cuet-phy-elec-field-07", "subtopic": "Field due to multiple charges", "topic_name": "Electric Field and Field Lines", "bloom_level": "apply", "options": [{"key": "A", "text": "2kQ/d², directed toward one charge", "is_correct": false}, {"key": "B", "text": "kQ/d², perpendicular to the line joining them", "is_correct": false}, {"key": "C", "text": "Zero", "is_correct": true}, {"key": "D", "text": "4kQ/d², directed along the line joining them", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "The two fields are equal in magnitude but opposite in direction (both point away from their respective +Q source). They cancel perfectly at the midpoint.", "misconception": "Adding magnitudes instead of considering vector directions"}, {"option_key": "B", "hint": "There is no physical reason for a perpendicular field at the midpoint of two charges on a line. By symmetry, any net field must be along the line.", "misconception": "Assuming field direction without analysis"}, {"option_key": "D", "hint": "4kQ/d² would require the fields to add (same direction), but they point in opposite directions from the midpoint.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The number of electric field lines emerging from a charge of +1 C in vacuum is:", "explanation": "By Gauss''s law, the total electric flux from a charge q is Φ = q/ε₀. For q = 1 C: Φ = 1/(8.85 × 10⁻¹²) = 1.13 × 10¹¹ N·m²/C. If we associate one field line per unit flux, the number of lines is q/ε₀ ≈ 1.13 × 10¹¹. This is conventionally written as 1/ε₀.", "correct_answer": "D", "concept_tags": ["field-lines-number", "gauss-law", "flux"], "payload": {"question_id": "cuet-phy-elec-field-08", "subtopic": "Quantitative field line concept", "topic_name": "Electric Field and Field Lines", "bloom_level": "apply", "options": [{"key": "A", "text": "1", "is_correct": false}, {"key": "B", "text": "4π", "is_correct": false}, {"key": "C", "text": "9 × 10⁹", "is_correct": false}, {"key": "D", "text": "1/ε₀ ≈ 1.13 × 10¹¹", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "1 field line for 1 C of charge would be far too few. The number is proportional to q/ε₀, which is a very large number.", "misconception": "Thinking one line per coulomb"}, {"option_key": "B", "hint": "4π appears in the factor 4πε₀ in Coulomb''s law, but the number of field lines from 1 C is 1/ε₀, not 4π.", "misconception": "Confusing 4π factor with the field line count"}, {"option_key": "C", "hint": "9 × 10⁹ is the Coulomb constant k = 1/(4πε₀), not 1/ε₀. The number of lines is 1/ε₀ = 4πk ≈ 1.13 × 10¹¹.", "misconception": "Using k instead of 1/ε₀"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "An electron is placed in a uniform electric field of 2 × 10⁴ N/C directed upward. The force on the electron is:", "explanation": "Force on charge q in field E: F = qE. For electron: F = eE = 1.6 × 10⁻¹⁹ × 2 × 10⁴ = 3.2 × 10⁻¹⁵ N. Since the electron is negative, the force is opposite to the field direction — i.e., downward. The force direction is opposite to E for negative charges.", "correct_answer": "A", "concept_tags": ["force-on-charge", "uniform-field", "electron"], "payload": {"question_id": "cuet-phy-elec-field-09", "subtopic": "Force on a charge in electric field", "topic_name": "Electric Field and Field Lines", "bloom_level": "apply", "options": [{"key": "A", "text": "3.2 × 10⁻¹⁵ N, directed downward", "is_correct": true}, {"key": "B", "text": "3.2 × 10⁻¹⁵ N, directed upward", "is_correct": false}, {"key": "C", "text": "1.6 × 10⁻¹⁵ N, directed downward", "is_correct": false}, {"key": "D", "text": "3.2 × 10⁻¹⁵ N, perpendicular to the field", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The magnitude is correct but the direction is wrong. Electrons (negative charge) experience force opposite to the electric field direction.", "misconception": "Forgetting that negative charges move opposite to the field"}, {"option_key": "C", "hint": "The direction is correct (downward) but the magnitude is halved. F = eE = 1.6×10⁻¹⁹ × 2×10⁴ = 3.2×10⁻¹⁵ N, not 1.6.", "misconception": "Arithmetic error in force calculation"}, {"option_key": "D", "hint": "The electric force on a charge always acts along the electric field (or opposite to it for negative charges), never perpendicular.", "misconception": "Confusing electric force with magnetic force (which is perpendicular)"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The electric field inside a uniformly charged thin spherical shell is:", "explanation": "By Gauss''s law, choosing a Gaussian surface inside the shell: the enclosed charge is zero (all charge is on the shell). Therefore, ∮E·dA = q_enc/ε₀ = 0, giving E = 0 everywhere inside. This is a fundamental result — a uniformly charged shell creates no field in its interior.", "correct_answer": "B", "concept_tags": ["spherical-shell", "gauss-law", "zero-field"], "payload": {"question_id": "cuet-phy-elec-field-10", "subtopic": "Field of symmetric charge distributions", "topic_name": "Electric Field and Field Lines", "bloom_level": "understand", "options": [{"key": "A", "text": "kQ/R², directed radially outward", "is_correct": false}, {"key": "B", "text": "Zero everywhere", "is_correct": true}, {"key": "C", "text": "kQ/r², where r is distance from centre", "is_correct": false}, {"key": "D", "text": "Proportional to r (increases linearly from centre)", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "kQ/R² is the field at the surface of the shell (r = R), not inside it.", "misconception": "Using the surface field value for interior points"}, {"option_key": "C", "hint": "kQ/r² is the field outside the shell (r > R). Inside (r < R), the enclosed charge is zero.", "misconception": "Confusing the outside field formula with the interior"}, {"option_key": "D", "hint": "Linear increase with r describes the field inside a uniformly charged solid sphere, not a hollow shell.", "misconception": "Confusing solid sphere with hollow shell"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "In a region where the electric field is uniform, the field lines are:", "explanation": "In a uniform electric field, the magnitude and direction of E are the same everywhere. Therefore, field lines must be equidistant (same density = same magnitude) and parallel (same direction). They are straight lines with equal spacing.", "correct_answer": "D", "concept_tags": ["uniform-field", "field-lines", "parallel-lines"], "payload": {"question_id": "cuet-phy-elec-field-11", "subtopic": "Properties of field lines", "topic_name": "Electric Field and Field Lines", "bloom_level": "understand", "options": [{"key": "A", "text": "Converging toward a point", "is_correct": false}, {"key": "B", "text": "Diverging from a point", "is_correct": false}, {"key": "C", "text": "Curved lines of varying spacing", "is_correct": false}, {"key": "D", "text": "Parallel, equally spaced straight lines", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Converging lines indicate increasing field strength in that direction, which contradicts the definition of a uniform field.", "misconception": "Confusing uniform field with the field near a negative charge"}, {"option_key": "B", "hint": "Diverging lines indicate a positive point charge source. Uniform field doesn''t diverge.", "misconception": "Confusing uniform field with radial field"}, {"option_key": "C", "hint": "Curved lines with varying spacing represent a non-uniform field (like near a charge or dipole).", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "The electric field on the axis of a uniformly charged disc of radius R and surface charge density σ, at a distance x from the centre (where x << R), is approximately:", "explanation": "The exact field on the axis of a charged disc is E = (σ/2ε₀)[1 − x/√(x² + R²)]. When x << R: √(x² + R²) ≈ R, so E ≈ (σ/2ε₀)[1 − x/R] ≈ σ/2ε₀ (since x/R → 0). This is the same as the field due to an infinite plane sheet of charge, which makes sense — close to the disc, it looks like an infinite plane.", "correct_answer": "C", "concept_tags": ["charged-disc", "infinite-plane-limit", "surface-charge"], "payload": {"question_id": "cuet-phy-elec-field-12", "subtopic": "Field of continuous distributions", "topic_name": "Electric Field and Field Lines", "bloom_level": "apply", "options": [{"key": "A", "text": "σ/ε₀", "is_correct": false}, {"key": "B", "text": "σx/(2ε₀R)", "is_correct": false}, {"key": "C", "text": "σ/(2ε₀)", "is_correct": true}, {"key": "D", "text": "Zero", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "σ/ε₀ is the field between two infinite parallel plates (complete enclosure), not on one side of a single disc.", "misconception": "Confusing single plane field with two-plate field"}, {"option_key": "B", "hint": "This expression goes to zero as x → 0, but the field near an infinite plane is constant (σ/2ε₀), not zero.", "misconception": null}, {"option_key": "D", "hint": "The field at any finite distance from a charged disc is non-zero. It approaches σ/2ε₀ as x → 0.", "misconception": "Thinking the field is zero on the surface of the disc"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A proton is released from rest in a uniform electric field of magnitude 8 × 10⁴ V/m. The acceleration of the proton is (mass of proton = 1.67 × 10⁻²⁷ kg):", "explanation": "Force on proton: F = eE = 1.6 × 10⁻¹⁹ × 8 × 10⁴ = 1.28 × 10⁻¹⁴ N. Acceleration: a = F/m = 1.28 × 10⁻¹⁴ / 1.67 × 10⁻²⁷ = 7.66 × 10¹² m/s². The proton accelerates in the direction of the field (since it''s positive).", "correct_answer": "B", "concept_tags": ["proton-acceleration", "uniform-field", "newton-second-law"], "payload": {"question_id": "cuet-phy-elec-field-13", "subtopic": "Motion of charges in electric fields", "topic_name": "Electric Field and Field Lines", "bloom_level": "apply", "options": [{"key": "A", "text": "7.66 × 10¹⁰ m/s²", "is_correct": false}, {"key": "B", "text": "7.66 × 10¹² m/s²", "is_correct": true}, {"key": "C", "text": "1.28 × 10⁻¹⁴ m/s²", "is_correct": false}, {"key": "D", "text": "7.66 × 10¹⁵ m/s²", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "10¹⁰ is two orders of magnitude too small. Check: 10⁻¹⁴/10⁻²⁷ = 10¹³, so the order should be ~10¹².", "misconception": "Exponent arithmetic error"}, {"option_key": "C", "hint": "1.28 × 10⁻¹⁴ N is the force, not the acceleration. You need to divide by mass.", "misconception": "Reporting force instead of acceleration"}, {"option_key": "D", "hint": "10¹⁵ is three orders too large — possibly from using electron mass instead of proton mass.", "misconception": "Using electron mass instead of proton mass"}]}}]'::jsonb, 'deploy-2026-03-05-b07');

SELECT insert_batch_questions('[{"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The electric field at a point on the equatorial line of a short electric dipole at distance r (r >> 2a) from the centre is E₁. If the point is now moved to the same distance r on the axial line, the electric field E₂ is:", "explanation": "For a short dipole at large distance r: Equatorial field E₁ = kp/r³. Axial field E₂ = 2kp/r³. Therefore E₂ = 2E₁. The axial field is always twice the equatorial field at the same distance from a dipole.", "correct_answer": "C", "concept_tags": ["dipole-field", "axial-equatorial", "ratio"], "payload": {"question_id": "cuet-phy-elec-field-14", "subtopic": "Dipole field comparison", "topic_name": "Electric Field and Field Lines", "bloom_level": "apply", "options": [{"key": "A", "text": "E₁/2", "is_correct": false}, {"key": "B", "text": "E₁", "is_correct": false}, {"key": "C", "text": "2E₁", "is_correct": true}, {"key": "D", "text": "4E₁", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "E₁/2 reverses the ratio. The axial field is stronger than equatorial, not weaker.", "misconception": "Inverting the axial-to-equatorial ratio"}, {"option_key": "B", "hint": "Equal fields would mean the axial and equatorial expressions are the same, but E_axial has a factor of 2 that E_equatorial doesn''t.", "misconception": "Assuming the field is the same in all directions at a given r"}, {"option_key": "D", "hint": "A factor of 4 would apply if the distance were halved (since E ∝ 1/r³), not for a change from equatorial to axial at the same r.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "An electric dipole is placed in a non-uniform electric field. The dipole will experience:", "explanation": "In a non-uniform field, the forces on the two charges of the dipole are unequal (since E differs at their positions). This produces both a net torque (trying to align the dipole with the field) AND a net translational force (since F₊ ≠ F₋). In contrast, a uniform field produces only torque (no net force). The dipole moves toward the region of stronger field.", "correct_answer": "A", "concept_tags": ["dipole-in-field", "non-uniform-field", "torque-and-force"], "payload": {"question_id": "cuet-phy-elec-field-15", "subtopic": "Dipole in external field", "topic_name": "Electric Field and Field Lines", "bloom_level": "analyze", "options": [{"key": "A", "text": "Both a net force and a net torque", "is_correct": true}, {"key": "B", "text": "Only a net torque, no net force", "is_correct": false}, {"key": "C", "text": "Only a net force, no net torque", "is_correct": false}, {"key": "D", "text": "Neither net force nor net torque", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "''Only torque, no force'' is true for a UNIFORM field. In a non-uniform field, the unequal forces on the two charges create a net translational force as well.", "misconception": "Applying the uniform-field result to a non-uniform field"}, {"option_key": "C", "hint": "The torque is always present (unless the dipole is already aligned with the field). There''s no scenario where there''s force but no torque in a non-uniform field.", "misconception": null}, {"option_key": "D", "hint": "A dipole in any external field (uniform or not) experiences at least a torque (unless aligned). In non-uniform fields, it also has a net force.", "misconception": "Thinking a dipole doesn''t interact with external fields"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The electric field inside a uniformly charged solid non-conducting sphere of radius R and total charge Q, at a distance r from the centre (r < R), is:", "explanation": "Using Gauss''s law with a spherical Gaussian surface of radius r inside the sphere: q_enc = Q(r³/R³) (charge enclosed proportional to volume). By Gauss''s law: E × 4πr² = Q(r³/R³)/ε₀. Solving: E = Qr/(4πε₀R³) = kQr/R³. The field increases linearly from centre to surface.", "correct_answer": "D", "concept_tags": ["solid-sphere", "gauss-law", "linear-field"], "payload": {"question_id": "cuet-phy-elec-field-16", "subtopic": "Gauss''s law applications", "topic_name": "Electric Field and Field Lines", "bloom_level": "apply", "options": [{"key": "A", "text": "kQ/r²", "is_correct": false}, {"key": "B", "text": "kQ/R²", "is_correct": false}, {"key": "C", "text": "Zero", "is_correct": false}, {"key": "D", "text": "kQr/R³", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "kQ/r² is the field OUTSIDE the sphere (r > R). Inside, only the enclosed charge contributes, which is less than Q.", "misconception": "Using total charge Q instead of enclosed charge for interior points"}, {"option_key": "B", "hint": "kQ/R² is the field at the surface (r = R). Inside, the field varies linearly with r, it''s not constant.", "misconception": "Using surface value for all interior points"}, {"option_key": "C", "hint": "Zero field inside applies to a conducting sphere or a hollow shell, not a solid non-conducting sphere with uniform volume charge.", "misconception": "Confusing non-conducting solid sphere with conducting sphere or shell"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The torque experienced by an electric dipole of moment p placed in a uniform electric field E at angle θ to the field is maximum when θ equals:", "explanation": "Torque τ = pE sinθ. This is maximum when sinθ = 1, i.e., θ = 90°. When the dipole is perpendicular to the field, the torque is maximum (τ_max = pE). At θ = 0° (aligned) or θ = 180° (anti-aligned), the torque is zero.", "correct_answer": "B", "concept_tags": ["dipole-torque", "maximum-torque", "angle"], "payload": {"question_id": "cuet-phy-elec-field-17", "subtopic": "Dipole in uniform field", "topic_name": "Electric Field and Field Lines", "bloom_level": "apply", "options": [{"key": "A", "text": "0°", "is_correct": false}, {"key": "B", "text": "90°", "is_correct": true}, {"key": "C", "text": "180°", "is_correct": false}, {"key": "D", "text": "45°", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "At θ = 0°, the dipole is aligned with the field and sin0° = 0, so the torque is zero (stable equilibrium).", "misconception": "Confusing equilibrium position with maximum torque position"}, {"option_key": "C", "hint": "At θ = 180°, sin180° = 0, so the torque is again zero (unstable equilibrium). Maximum torque requires sinθ = 1.", "misconception": "Confusing unstable equilibrium with maximum torque"}, {"option_key": "D", "hint": "At 45°, sin45° = 1/√2, which gives τ = pE/√2 — this is about 71% of maximum, not the maximum itself.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "hard", "question_text": "The electric field due to an infinitely long straight wire with uniform linear charge density λ at perpendicular distance r from the wire is:", "explanation": "Using Gauss''s law with a cylindrical Gaussian surface of radius r and length l: E × 2πrl = λl/ε₀. Solving: E = λ/(2πε₀r). The field is directed radially outward (for positive λ) and falls off as 1/r — slower than the 1/r² of a point charge.", "correct_answer": "A", "concept_tags": ["infinite-wire", "gauss-law", "linear-charge-density"], "payload": {"question_id": "cuet-phy-elec-field-18", "subtopic": "Field of symmetric distributions", "topic_name": "Electric Field and Field Lines", "bloom_level": "apply", "options": [{"key": "A", "text": "λ/(2πε₀r)", "is_correct": true}, {"key": "B", "text": "λ/(4πε₀r²)", "is_correct": false}, {"key": "C", "text": "λ/(ε₀r)", "is_correct": false}, {"key": "D", "text": "λ/(4πε₀r)", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This has 1/r² dependence (like a point charge) and uses 4πε₀ in the denominator. The wire field has 1/r dependence and 2πε₀.", "misconception": "Applying point charge formula to a line charge"}, {"option_key": "C", "hint": "λ/ε₀r is missing the factor of 2π from the cylindrical Gaussian surface area (2πrl).", "misconception": "Incorrect Gaussian surface area calculation"}, {"option_key": "D", "hint": "4πε₀r uses the wrong geometric factor. For cylindrical symmetry, the surface area gives 2πrl, leading to 2πε₀ in the denominator.", "misconception": "Using the spherical factor 4πε₀ for a cylindrical problem"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): The electric field at a point on the surface of a charged conductor is perpendicular to the surface.\nReason (R): If there were a tangential component of the field, the free charges on the conductor surface would move, contradicting electrostatic equilibrium.", "explanation": "Both A and R are correct, and R is the correct explanation of A. In electrostatic equilibrium, charges on a conductor are stationary. If E had a tangential component at the surface, it would exert a force on the free charges, causing them to move — violating the assumption of static equilibrium. Therefore, E must be perpendicular to the surface.", "correct_answer": "A", "concept_tags": ["conductor-surface", "perpendicular-field", "equilibrium"], "payload": {"question_id": "cuet-phy-elec-field-19", "subtopic": "Conductors in electrostatic equilibrium", "topic_name": "Electric Field and Field Lines", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "R directly explains A — the absence of tangential force (which would move charges) is exactly why the field must be perpendicular.", "misconception": "Not recognising the causal connection between charge motion and field direction"}, {"option_key": "C", "hint": "R is factually correct — free charges would indeed move if there were a tangential field component.", "misconception": null}, {"option_key": "D", "hint": "A is correct — electric field is always perpendicular to a conductor surface in electrostatic equilibrium.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "hard", "question_text": "Assertion (A): The density of electric field lines is proportional to the magnitude of the electric field at that point.\nReason (R): Electric field lines are drawn such that the number of lines per unit cross-sectional area is proportional to E.", "explanation": "Both A and R are correct, and R correctly explains A. By convention, field lines are drawn so that the number of lines crossing a unit area perpendicular to the lines equals the field magnitude. This is why regions of closely spaced lines have stronger fields, and widely spaced lines indicate weaker fields.", "correct_answer": "A", "concept_tags": ["field-line-density", "field-magnitude", "convention"], "payload": {"question_id": "cuet-phy-elec-field-20", "subtopic": "Field line interpretation", "topic_name": "Electric Field and Field Lines", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "R is precisely the convention that makes A true — the density of field lines represents field strength because they are drawn that way. R explains A.", "misconception": "Not seeing that R is the definition that makes A true"}, {"option_key": "C", "hint": "R is correct — this is the standard convention for drawing field lines in physics.", "misconception": null}, {"option_key": "D", "hint": "A is correct — field line density does represent field magnitude. This is how field maps work.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "easy", "question_text": "The electric field between two large parallel plates carrying equal and opposite surface charge densities +σ and −σ is:", "explanation": "Each plate produces a field σ/(2ε₀). Between the plates, both fields point in the same direction (from + to − plate), so they add: E = σ/(2ε₀) + σ/(2ε₀) = σ/ε₀. Outside the plates, the fields cancel. This is the basis of a parallel plate capacitor.", "correct_answer": "C", "concept_tags": ["parallel-plates", "superposition", "uniform-field"], "payload": {"question_id": "cuet-phy-elec-field-21", "subtopic": "Field between parallel plates", "topic_name": "Electric Field and Field Lines", "bloom_level": "understand", "options": [{"key": "A", "text": "σ/(2ε₀)", "is_correct": false}, {"key": "B", "text": "2σ/ε₀", "is_correct": false}, {"key": "C", "text": "σ/ε₀", "is_correct": true}, {"key": "D", "text": "Zero", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "σ/(2ε₀) is the field due to a single infinite plate. Between two oppositely charged plates, both fields add up.", "misconception": "Considering only one plate instead of both"}, {"option_key": "B", "hint": "2σ/ε₀ would arise from incorrectly doubling the combined field. Each plate contributes σ/(2ε₀), and the total is σ/ε₀.", "misconception": "Double-counting the field contributions"}, {"option_key": "D", "hint": "Zero field exists outside the plates (fields cancel), not between them. Between the plates, the fields reinforce.", "misconception": "Confusing the region between the plates with the region outside"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "mcq", "difficulty": "medium", "question_text": "A charge q is placed at the centre of a cube. The electric flux through one face of the cube is:", "explanation": "By Gauss''s law, total flux through the cube = q/ε₀. By symmetry, the cube has 6 identical faces, so flux through each face = q/(6ε₀). This is a standard application of Gauss''s law using symmetry arguments.", "correct_answer": "D", "concept_tags": ["gauss-law", "flux-through-face", "symmetry", "cube"], "payload": {"question_id": "cuet-phy-elec-field-22", "subtopic": "Electric flux and Gauss''s law", "topic_name": "Electric Field and Field Lines", "bloom_level": "apply", "options": [{"key": "A", "text": "q/ε₀", "is_correct": false}, {"key": "B", "text": "q/(2ε₀)", "is_correct": false}, {"key": "C", "text": "q/(4ε₀)", "is_correct": false}, {"key": "D", "text": "q/(6ε₀)", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "q/ε₀ is the total flux through all 6 faces, not just one face.", "misconception": "Using total flux instead of dividing by the number of faces"}, {"option_key": "B", "hint": "Dividing by 2 suggests only 2 faces, but a cube has 6 symmetric faces.", "misconception": "Dividing by 2 instead of 6"}, {"option_key": "C", "hint": "Dividing by 4 suggests 4 faces. A cube has 6 faces, each receiving an equal share of flux.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "easy", "question_text": "The diagram shows electric field line patterns near different charge configurations. Which pattern correctly represents the field lines of a single isolated positive charge?", "explanation": "A single positive charge produces radial field lines pointing outward in all directions. Pattern B (radial outward) is correct. Pattern A shows a negative charge (lines inward). Pattern C shows magnetic field lines (closed loops). Pattern D shows a uniform field.", "correct_answer": "B", "concept_tags": ["field-line-pattern", "positive-charge", "radial-field"], "payload": {"question_id": "cuet-phy-elec-field-23", "subtopic": "Field lines of simple charge distributions", "topic_name": "Electric Field and Field Lines", "bloom_level": "remember", "options": [{"key": "A", "text": "Lines converging inward", "is_correct": false}, {"key": "B", "text": "Radial lines going outward", "is_correct": true}, {"key": "C", "text": "Closed circular loops", "is_correct": false}, {"key": "D", "text": "Parallel straight lines", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Lines converging inward represent the field of a negative charge, not positive. Positive charges are sources, not sinks.", "misconception": "Confusing positive and negative charge field patterns"}, {"option_key": "C", "hint": "Electric field lines never form closed loops — that is a property of magnetic field lines.", "misconception": "Confusing electric field lines with magnetic field lines"}, {"option_key": "D", "hint": "Parallel lines represent a uniform field (like between capacitor plates), not the radial field of a point charge.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "medium", "question_text": "The diagram shows the electric field lines between two charges. The field lines start from a charge on the left and end on a charge on the right, with the lines curving outward between them. Which of the following correctly describes the two charges?", "explanation": "Field lines originate from positive charges and terminate on negative charges. Since lines start from the left charge, it is positive. Since they end on the right charge, it is negative. The charges form a dipole.", "correct_answer": "C", "concept_tags": ["field-line-interpretation", "dipole-pattern", "charge-identification"], "payload": {"question_id": "cuet-phy-elec-field-24", "subtopic": "Interpreting field line diagrams", "topic_name": "Electric Field and Field Lines", "bloom_level": "understand", "options": [{"key": "A", "text": "Both charges are positive", "is_correct": false}, {"key": "B", "text": "Both charges are negative", "is_correct": false}, {"key": "C", "text": "Left is positive, right is negative", "is_correct": true}, {"key": "D", "text": "Left is negative, right is positive", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "If both were positive, field lines would diverge from both charges and never terminate on either — they would extend to infinity.", "misconception": "Not knowing that field lines terminate on negative charges"}, {"option_key": "B", "hint": "If both were negative, field lines would converge on both and originate from infinity — they wouldn''t start from either charge.", "misconception": null}, {"option_key": "D", "hint": "This reverses the convention. Lines emerge from positive charges (where they start) and enter negative charges (where they end).", "misconception": "Reversing the start/end convention for field lines"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "medium", "question_text": "The figure shows the variation of electric field E with distance r from the centre of a charged sphere. The graph shows E increasing linearly from r = 0 to r = R, then decreasing as 1/r² for r > R. This graph represents the electric field of:", "explanation": "Inside a uniformly charged non-conducting solid sphere: E = kQr/R³ (linear increase). Outside: E = kQ/r² (inverse square decrease). Maximum occurs at the surface (r = R). This is distinctly different from a conducting sphere (E = 0 for r < R) or a shell (E = 0 for r < R).", "correct_answer": "D", "concept_tags": ["solid-sphere", "E-vs-r-graph", "non-conducting"], "payload": {"question_id": "cuet-phy-elec-field-25", "subtopic": "Graphical analysis of electric field", "topic_name": "Electric Field and Field Lines", "bloom_level": "analyze", "options": [{"key": "A", "text": "A uniformly charged conducting sphere", "is_correct": false}, {"key": "B", "text": "A thin uniformly charged spherical shell", "is_correct": false}, {"key": "C", "text": "A point charge at the origin", "is_correct": false}, {"key": "D", "text": "A uniformly charged non-conducting solid sphere", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "Inside a conducting sphere, E = 0 (no field). The graph shows E increasing linearly from centre, which means charge is distributed throughout the volume.", "misconception": "Confusing conducting sphere with non-conducting solid sphere"}, {"option_key": "B", "hint": "Inside a thin shell, E = 0 (no enclosed charge). The graph shows non-zero E inside, indicating volume charge distribution.", "misconception": "Confusing shell with solid sphere"}, {"option_key": "C", "hint": "A point charge has E = kq/r² everywhere (no linear region). The graph''s linear rise indicates distributed charge.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "diagram-based", "difficulty": "hard", "question_text": "The figure shows equipotential surfaces (V₁ > V₂ > V₃) that are concentric circles, with V₁ being the innermost. The spacing between adjacent surfaces decreases as we move outward. What can be concluded about the electric field?", "explanation": "E = −dV/dr, so the field is stronger where equipotential surfaces are closer together. Since spacing decreases outward, the field increases outward. The field is directed radially inward (from high V to low V means inward toward centre — wait, V₁ > V₂ > V₃ with V₁ innermost means potential decreases outward, so E points outward (from high to low potential). But the spacing DECREASES outward, meaning E INCREASES. Actually, this contradicts a normal positive point charge (where E decreases). This pattern could represent the interior of a non-conducting charged sphere where E increases linearly outward.", "correct_answer": "A", "concept_tags": ["equipotential-surfaces", "field-gradient", "non-uniform-field"], "payload": {"question_id": "cuet-phy-elec-field-26", "subtopic": "Equipotential surfaces and field", "topic_name": "Electric Field and Field Lines", "bloom_level": "analyze", "options": [{"key": "A", "text": "The field is directed radially outward and increases with distance from the centre", "is_correct": true}, {"key": "B", "text": "The field is directed radially inward and decreases with distance", "is_correct": false}, {"key": "C", "text": "The field is uniform throughout the region", "is_correct": false}, {"key": "D", "text": "The field is directed radially outward and decreases with distance from the centre", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "Since V decreases outward (V₁ > V₂ > V₃), E = −dV/dr points outward (in the direction of decreasing V), not inward.", "misconception": "Getting the direction of E wrong relative to the potential gradient"}, {"option_key": "C", "hint": "In a uniform field, equipotential surfaces are equally spaced planes. Here, the spacing varies, indicating a non-uniform field.", "misconception": "Thinking unequal spacing can represent a uniform field"}, {"option_key": "D", "hint": "If E decreased with distance, the equipotential surfaces would get farther apart (not closer), since |ΔV| = E·Δr.", "misconception": "Confusing closer spacing with weaker field instead of stronger field"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): Electric field lines are always perpendicular to equipotential surfaces.\nReason (R): No work is done in moving a charge along an equipotential surface.", "explanation": "Both A and R are correct, and R explains A. On an equipotential surface, V is constant, so dV = 0. Work done dW = q·dV = 0. Since W = F·ds·cosθ = qE·ds·cosθ = 0 and q ≠ 0, ds ≠ 0, E ≠ 0, we need cosθ = 0, meaning θ = 90°. Therefore E is perpendicular to the surface.", "correct_answer": "B", "concept_tags": ["equipotential", "perpendicularity", "work-done"], "payload": {"question_id": "cuet-phy-elec-field-27", "subtopic": "Equipotential surfaces", "topic_name": "Electric Field and Field Lines", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": false}, {"key": "B", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": true}, {"key": "C", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "D", "text": "A is incorrect but R is correct", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "R is correct — by definition, potential is constant on an equipotential surface, so work done in moving a charge along it is zero.", "misconception": "Thinking work is done along equipotential surfaces"}, {"option_key": "C", "hint": "A is correct — it is a standard result that E is perpendicular to equipotential surfaces. This follows directly from E = −∇V.", "misconception": null}, {"option_key": "D", "hint": "Read carefully — this option says the same as B. Both state R correctly explains A, which is true.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "assertion-reasoning", "difficulty": "medium", "question_text": "Assertion (A): Electrostatic field lines do not form closed loops.\nReason (R): The electrostatic field is conservative in nature.", "explanation": "Both A and R are correct, and R correctly explains A. A conservative field has zero circulation: ∮E·dl = 0. If field lines formed closed loops, this integral would be non-zero (positive work done around the loop), contradicting the conservative nature. Hence, electrostatic field lines are open — they start on positive charges and end on negative charges.", "correct_answer": "D", "concept_tags": ["conservative-field", "closed-loops", "circulation"], "payload": {"question_id": "cuet-phy-elec-field-28", "subtopic": "Nature of electrostatic field", "topic_name": "Electric Field and Field Lines", "bloom_level": "understand", "options": [{"key": "A", "text": "Both A and R are correct but R is NOT the correct explanation of A", "is_correct": false}, {"key": "B", "text": "A is correct but R is incorrect", "is_correct": false}, {"key": "C", "text": "A is incorrect but R is correct", "is_correct": false}, {"key": "D", "text": "Both A and R are correct and R is the correct explanation of A", "is_correct": true}], "elimination_hints": [{"option_key": "A", "hint": "The conservative nature IS the reason field lines can''t form closed loops — zero circulation means no closed paths. R directly explains A.", "misconception": "Not seeing the connection between conservative fields and open field lines"}, {"option_key": "B", "hint": "R is correct — the electrostatic field is indeed conservative (curl E = 0).", "misconception": null}, {"option_key": "C", "hint": "A is correct — electrostatic field lines never form closed loops, unlike magnetic field lines.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "medium", "question_text": "Match the charge distribution in Column I with the distance dependence of its electric field in Column II:\n\nColumn I:\nP. Point charge\nQ. Infinite line charge\nR. Infinite plane sheet\nS. Electric dipole (far field)\n\nColumn II:\n1. E ∝ 1/r\n2. E ∝ 1/r²\n3. E ∝ 1/r³\n4. E is constant (independent of r)", "explanation": "Point charge: E = kq/r² → P-2. Infinite line charge: E = λ/(2πε₀r) → Q-1. Infinite plane: E = σ/(2ε₀) → R-4 (constant). Dipole far field: E ∝ 1/r³ → S-3.", "correct_answer": "B", "concept_tags": ["distance-dependence", "field-expressions", "charge-distributions"], "payload": {"question_id": "cuet-phy-elec-field-29", "subtopic": "Comparison of field expressions", "topic_name": "Electric Field and Field Lines", "bloom_level": "analyze", "options": [{"key": "A", "text": "P-2, Q-3, R-4, S-1", "is_correct": false}, {"key": "B", "text": "P-2, Q-1, R-4, S-3", "is_correct": true}, {"key": "C", "text": "P-1, Q-2, R-3, S-4", "is_correct": false}, {"key": "D", "text": "P-3, Q-1, R-4, S-2", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This assigns 1/r³ to line charge and 1/r to dipole. Line charge has 1/r (slower decay), dipole has 1/r³ (faster decay).", "misconception": "Swapping line charge and dipole field dependences"}, {"option_key": "C", "hint": "This assigns 1/r to point charge, but E ∝ 1/r² for a point charge (inverse square law).", "misconception": "Confusing point charge field with line charge field"}, {"option_key": "D", "hint": "This assigns 1/r³ to point charge and 1/r² to dipole. The point charge has 1/r² and the dipole has 1/r³.", "misconception": "Swapping point charge and dipole field dependences"}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "match-the-following", "difficulty": "hard", "question_text": "Match the physical situation in Column I with the correct statement about electric field in Column II:\n\nColumn I:\nP. Inside a charged conducting sphere\nQ. Inside a uniformly charged non-conducting solid sphere\nR. Between parallel plates (+σ and −σ)\nS. Outside a spherical shell at distance r > R\n\nColumn II:\n1. E = kQ/r² (same as point charge)\n2. E = 0\n3. E = σ/ε₀ (uniform)\n4. E increases linearly with distance from centre", "explanation": "Inside a conducting sphere: E = 0 (P-2). Inside a non-conducting solid sphere: E = kQr/R³, linearly increasing (Q-4). Between parallel plates: E = σ/ε₀, uniform (R-3). Outside a shell: E = kQ/r², same as point charge (S-1).", "correct_answer": "C", "concept_tags": ["gauss-law-applications", "field-comparison", "conductor-vs-insulator"], "payload": {"question_id": "cuet-phy-elec-field-30", "subtopic": "Electric field in various geometries", "topic_name": "Electric Field and Field Lines", "bloom_level": "analyze", "options": [{"key": "A", "text": "P-2, Q-1, R-3, S-4", "is_correct": false}, {"key": "B", "text": "P-4, Q-2, R-3, S-1", "is_correct": false}, {"key": "C", "text": "P-2, Q-4, R-3, S-1", "is_correct": true}, {"key": "D", "text": "P-2, Q-3, R-4, S-1", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "This assigns kQ/r² to inside a solid sphere, but inside a solid sphere E increases linearly with r, not as 1/r².", "misconception": "Using the external field formula for interior points"}, {"option_key": "B", "hint": "This assigns linearly increasing field to inside a conductor. Inside a conductor, E = 0 always (charges reside on the surface).", "misconception": "Confusing conductor with non-conducting solid sphere"}, {"option_key": "D", "hint": "This swaps the field between parallel plates (σ/ε₀) with the solid sphere interior (linear). The plates give uniform field, the solid sphere gives linear.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "Electric field lines always originate from positive charges and terminate on negative charges.", "explanation": "This statement is TRUE. By convention, electric field lines emerge from positive charges (sources) and end on negative charges (sinks). If no negative charge is present, lines extend to infinity. This is a fundamental property of electrostatic field lines.", "correct_answer": "A", "concept_tags": ["field-line-convention", "positive-negative-charges"], "payload": {"question_id": "cuet-phy-elec-field-31", "subtopic": "Properties of electric field lines", "topic_name": "Electric Field and Field Lines", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "This is a correct and fundamental property of electrostatic field lines — they originate from positive and terminate on negative charges.", "misconception": "Thinking field lines can originate from negative charges or form loops"}, {"option_key": "C", "hint": "This option is not applicable for true/false questions.", "misconception": null}, {"option_key": "D", "hint": "This option is not applicable for true/false questions.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The total electric flux through a closed surface depends on the shape and size of the surface.", "explanation": "This statement is FALSE. By Gauss''s law, the total electric flux through any closed surface Φ = q_enc/ε₀, which depends ONLY on the net charge enclosed, not on the shape or size of the surface. A large sphere and a small cube enclosing the same charge will have the same total flux.", "correct_answer": "B", "concept_tags": ["gauss-law", "electric-flux", "closed-surface"], "payload": {"question_id": "cuet-phy-elec-field-32", "subtopic": "Gauss''s law fundamentals", "topic_name": "Electric Field and Field Lines", "bloom_level": "understand", "options": [{"key": "A", "text": "True", "is_correct": false}, {"key": "B", "text": "False", "is_correct": true}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "A", "hint": "Gauss''s law states Φ = q_enc/ε₀. The flux depends only on enclosed charge, not on the surface geometry.", "misconception": "Confusing flux density (which varies over a surface) with total flux (which depends only on enclosed charge)"}, {"option_key": "C", "hint": "This option is not applicable for true/false questions.", "misconception": null}, {"option_key": "D", "hint": "This option is not applicable for true/false questions.", "misconception": null}]}}, {"chapter_id": "cuet-phy-electrostatics", "topic_id": "cuet-phy-es-field", "exam_ids": ["CUET", "NEET"], "question_type": "true-false", "difficulty": "easy", "question_text": "The electric field at a point due to a positive charge is directed away from the charge.", "explanation": "This statement is TRUE. A positive charge repels a positive test charge. Since the electric field direction is defined as the direction of force on a positive test charge, the field points radially away from a positive source charge.", "correct_answer": "A", "concept_tags": ["field-direction", "positive-charge", "convention"], "payload": {"question_id": "cuet-phy-elec-field-33", "subtopic": "Direction of electric field", "topic_name": "Electric Field and Field Lines", "bloom_level": "remember", "options": [{"key": "A", "text": "True", "is_correct": true}, {"key": "B", "text": "False", "is_correct": false}, {"key": "C", "text": "---", "is_correct": false}, {"key": "D", "text": "---", "is_correct": false}], "elimination_hints": [{"option_key": "B", "hint": "The electric field from a positive charge points outward (away). For a negative charge, it points inward (toward the charge).", "misconception": "Confusing the field direction of positive and negative charges"}, {"option_key": "C", "hint": "This option is not applicable for true/false questions.", "misconception": null}, {"option_key": "D", "hint": "This option is not applicable for true/false questions.", "misconception": null}]}}]'::jsonb, 'deploy-2026-03-05-b07');

